   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748264573909-NQ9B4Y93RR3RPPM2KVW2/%40c.shoots.shows+-+High+Regard+-+Green+Door+Store+-+23.05.2025+-+019.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748264574014-5095DPYJQGX8G4OHNL53/%40c.shoots.shows+-+High+Regard+-+Green+Door+Store+-+23.05.2025+-+020.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748264575104-9XIBSZ1VWP5WFQV7MPCH/%40c.shoots.shows+-+High+Regard+-+Green+Door+Store+-+23.05.2025+-+001.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748264575145-Y479JRF62ZI22EOG6U2E/%40c.shoots.shows+-+High+Regard+-+Green+Door+Store+-+23.05.2025+-+002.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748264576276-JBCV4J5ZSPVKB6WN6VDM/%40c.shoots.shows+-+High+Regard+-+Green+Door+Store+-+23.05.2025+-+003.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748264576451-82HYDPKHP0WCI1RJ24EK/%40c.shoots.shows+-+High+Regard+-+Green+Door+Store+-+23.05.2025+-+004.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748264577300-HG0RFHPAU9NYEDEMQEVV/%40c.shoots.shows+-+High+Regard+-+Green+Door+Store+-+23.05.2025+-+005.jpg?format=original" />
  

  
