   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748264578188-UXX8Y3QN6BAMSISEVWTG/%40c.shoots.shows+-+High+Regard+-+Green+Door+Store+-+23.05.2025+-+007.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748264578688-46X7ZKFLI4109M4QTCQJ/%40c.shoots.shows+-+High+Regard+-+Green+Door+Store+-+23.05.2025+-+008.jpg?format=original" />
  

  
