INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Big Special Live @ Oslo Hackney - 05/05/2025',
  'big-special-live-oslo-hackney-05-05-25',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><a href="https://open.spotify.com/artist/3hmNB1OCsGQVf8ttZy01e2?si=saFOKDwzRl-r-8_yCQseRA" target="_blank">Big Special</a> tore through a sold-out set at Oslo Hackney on May 5, 2025, turning the venue into a full-blown pressure cooker. Support came from <a href="https://open.spotify.com/artist/6oaEXmqVM7eQnzva7kHudo?si=eSDWyrCpT9OzRkSSrxF-Gg" target="_blank"><em>Good Health Good Wealth</em></a>, whose sharp, confident set did a great job of setting the pace for the night ahead.</p><p class="" style="white-space:pre-wrap;">The room was packed, the crowd was up for it, and from the first note, the energy didn’t let up. Oslo’s lighting and sound were dialled in perfectly, which made all the difference as the chaos started to build.</p></div>

