INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Big Special Surprise Drop “National Average” Album',
  'big-special-surprise-drop-national-average-album',
  '<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/61e7f776-1291-46b8-bb3d-d9f3aa46d286/515497036_1112074770744554_406797124511873189_n.jpg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Big Special made a splash last week (4th July 2025), unexpectedly releasing “<a href="https://open.spotify.com/album/2wHHIEXgiVxTRS2EjFzMmo?si=hCX7AfduScGxPxRHu_pTRQ"><span style="text-decoration:underline"><strong>National Average</strong></span></a>”, their highly-anticipated follow-up to the acclaimed 2024 album, “Postindustrial Hometown Blues.” In classic Big Special style, the album arrived without fanfare or prior announcement, instantly creating buzz among fans and music critics alike.</p><p class="" style="white-space:pre-wrap;">“National Average” retains the gritty authenticity and lyrical punch Big Special fans have come to adore, while also showcasing the band''s evolving sound, blending sharp commentary with raw musical energy. Early standout tracks include the provocative opener "<a href="https://open.spotify.com/track/5H0U1YTRxfzoycXUb2nlUl?si=8c01a205214b46b2"><span style="text-decoration:underline"><strong>THE MESS</strong></span></a>" and the punchy anthem "<a href="https://open.spotify.com/track/64J1EYisViSUN0LydKHenz?si=7cd273f78a564fef"><span style="text-decoration:underline"><strong>SHOP MUSIC</strong></span></a>" both capturing the band''s distinctive knack for channelling the pulse of contemporary life.</p><p class="" style="white-space:pre-wrap;">The surprise release strategy, reminiscent of Big Special’s energetic live sets and their well-known affinity for spontaneity, has fans eagerly streaming the new tracks. Critics are already praising the record’s candid reflection on everyday struggles and societal discontent, marking it as another significant milestone for the band.</p><p class="" style="white-space:pre-wrap;">You can stream <strong>“</strong><a href="https://open.spotify.com/album/2wHHIEXgiVxTRS2EjFzMmo?si=hCX7AfduScGxPxRHu_pTRQ"><span style="text-decoration:underline"><strong>National Average</strong></span></a><strong>”</strong> now—experience Big Special’s newest offering below:</p></div><iframe style="border-radius:12px" src="https://open.spotify.com/embed/album/2wHHIEXgiVxTRS2EjFzMmo?utm_source=generator" width="100%" height="352" frameBorder="0" allowfullscreen="" allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture" loading="lazy"></iframe><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Don’t miss Big Special performing these fresh tracks live—check their website for upcoming tour dates, and grab tickets fast as their gigs are known to sell out quickly.</p></div><a href="https://www.songkick.com/artists/10253312-big-special" class="songkick-widget" data-theme="light" data-track-button="on" data-detect-style="false" data-background-color="transparent" data-locale="en"></a><script src="//widget.songkick.com/10253312/widget.js"></script>',
  'Big Special made a splash last week (4th July 2025), unexpectedly releasing “National Average”, their highly-anticipated follow-up to the acclaimed 2024 album, “Postindustrial Hometown Blues.” In classic Big Special style, the album arrived without fanfare or prior announcement, instantly creating b',
  'Feats.',
  '2025-07-07 10:00:00',
  'Album Release, New Music, up and coming, ONES TO WATCH',
  '/images/articles/515497036_1112074770744554_406797124511873189_n.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Black Honey Announce Intimate April Tour, Call for Support Acts via TikTok',
  'black-honey-announce-intimate-april-tour',
  '<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/64db88c7-0b77-4d2a-87b1-4686486b9e5b/blackhoneyTour.jpg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Black Honey have announced a return to the stage this April with a series of intimate UK shows, marking their first live appearances since wrapping the <em>A Fistful of Peaches</em> era. The Brighton four-piece will play <a href="https://www.songkick.com/concerts/42513426-black-honey-at-night-and-day" target="_blank">Manchester’s Night &amp; Day (April 15)</a>, <a href="https://www.songkick.com/concerts/42513071-black-honey-at-patterns" target="_blank">Brighton’s Patterns (April 16)</a>, and <a href="https://www.songkick.com/concerts/42513399-black-honey-at-omeara" target="_blank">London’s Omeara (April 17)</a>.</p><p class="" style="white-space:pre-wrap;">Coinciding with the tour announcement, <a href="https://open.spotify.com/track/3yTI3OvnXDJsTusEqkVaNt?si=197fde7dca4b4703" target="_blank">the band released a new single titled “Psycho”</a> — a theatrical track that frontwoman Izzy B. Phillips describes in <a href="https://readdork.com/news/black-honey-psycho-uk-shows/" target="_blank">an article for DORK</a> as “a rabbit hole of voyeurism, nihilism and existentialism.” The accompanying video, directed by Harv Frost, leans heavily into dystopian visuals and confrontational energy, marking a bold new chapter in the band’s creative evolution.</p><p class="" style="white-space:pre-wrap;">What makes this run of shows stand out is the way Black Honey are curating their support acts. Instead of turning to management or label rosters, the band are asking unsigned artists to pitch themselves directly via TikTok. In a post shared to the platform, Phillips said: “We want to give someone an opportunity to put you in front of our fans.”</p></div><blockquote class="tiktok-embed" cite="https://www.tiktok.com/@blackhoneyuk/video/7488736976095464726" data-video-id="7488736976095464726" style="max-width: 605px;min-width: 325px;" > <section> <a target="_blank" title="@blackhoneyuk" href="https://www.tiktok.com/@blackhoneyuk?refer=embed">@blackhoneyuk</a> <p>Tag them pls </p> <a target="_blank" title="♬ original sound - Blackhoneyuk" href="https://www.tiktok.com/music/original-sound-7488736967088769814?refer=embed">♬ original sound - Blackhoneyuk</a> </section> </blockquote> <script async src="https://www.tiktok.com/embed.js"></script><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">It’s a clear signal of the band’s interest in supporting emerging voices — and a recognition of how artists are increasingly turning to digital platforms for discovery and connection. With TikTok’s reach and informal tone, the callout has opened the door for a diverse range of acts to submit their work directly to the band.</p><p class="" style="white-space:pre-wrap;">While the selection process remains in the band’s hands, this approach places Black Honey in a growing group of artists using social media not just for promotion, but for grassroots collaboration. The initiative offers fans an added layer of anticipation: the chance to witness up-and-coming acts handpicked by the headliners themselves.</p><p class="" style="white-space:pre-wrap;">Black Honey’s April shows will likely blend new material with crowd favourites, and this refreshed approach to tour curation shows a band both in touch with their community and keen to challenge the conventions of touring. With “Psycho” setting the tone — both sonically and visually — it’s clear they’re entering 2025 with intent.</p><p class="" style="white-space:pre-wrap;"><a href="https://www.bandsintown.com/a/1127942-black-honey" target="_blank">Tickets are on sale now.</a></p></div><script charset="utf-8" src="https://widget.bandsintown.com/main.min.js"></script><a class="bit-widget-initializer" data-artist-name="Black Honey" data-display-local-dates="false" data-display-past-dates="false" data-auto-style="false" data-text-color="#000000" data-link-color="#00b4b3" data-background-color="rgba(0,0,0,0)" data-display-limit="15" data-display-start-time="true" data-link-text-color="#FFFFFF" data-display-lineup="false" data-display-play-my-city="true" data-separator-color="rgba(255, 255, 255, 0.5)"></a><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><br><br><br><br></p></div>',
  'Black Honey have announced a return to the stage this April with a series of intimate UK shows, marking their first live appearances since wrapping the A Fistful of Peaches era. The Brighton four-piece will play Manchester’s Night &amp; Day (April 15), Brighton’s Patterns (April 16), and London’s Om',
  'Feats.',
  '2025-04-11 10:00:00',
  'News, Tour, Release Radar',
  '/images/articles/blackhoneyTour.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Bloodstock 2025: Heavy Hitters and Hidden Gems',
  'bloodstock-2025-heavy-hitters-and-hidden-gems',
  '<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/76eb1e3e-5a86-47b8-99e1-085ef7ce0f2d/480227114_1166097371544839_6881514108013743355_n.jpg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Yet, Bloodstock’s true charm lies in its passionate promotion of emerging talent, with many promising bands appearing on its stages. On the Ronnie James Dio Stage, the British 4-piece band <a href="https://open.spotify.com/artist/49O77SKrEk1b9sNjhI0kM4?si=LXUptjsMRvmHJe_OOxHU7Q"><span style="text-decoration:underline"><strong>Heriot</strong> </span></a>are unquestionably ones to watch. Their fusion of hardcore, death metal, and experimental influences ensures they''ll leave a lasting impression. <a href="https://open.spotify.com/artist/35GpJabAKuETXnWsWQbTjr?si=cFLiqEv-RV-Jf3VeTWoj3Q"><span style="text-decoration:underline"><strong>Cage Fight</strong></span></a> are equally compelling, delivering a fierce brand of crossover thrash that''s rapidly gaining traction. Brighton-based "doom rockers" <a href="https://open.spotify.com/artist/72ThxubT9T0hqFUi1gU89d?si=gKvgGKkSTxqG_JybEFy3hw"><span style="text-decoration:underline"><strong>Famyne</strong></span></a> also grace the Ronnie James Dio Stage, offering richly atmospheric sets that promise to captivate those looking for a deeper, darker sound.</p><p class="" style="white-space:pre-wrap;">The Sophie Lancaster Stage once again highlights groundbreaking and diverse acts. <a href="https://open.spotify.com/artist/7F8CwvvwIi7GJvZ7qD2ybR?si=aGzzaB0RTzi-r_WWVgC7fw"><span style="text-decoration:underline"><strong>Pengshui</strong> </span></a>are poised to become festival favourites, merging grime, punk, and metal into an electrifying live experience. Another standout on this stage is <a href="https://open.spotify.com/artist/5sW5eR9g4kNibasfrlw4EN?si=27H8vvUIRj-B2M1FqkoyPA"><span style="text-decoration:underline"><strong>Spirit Adrift</strong></span></a>, whose powerful melodies and classic metal influences have already earned them considerable acclaim, positioning them perfectly for broader recognition.</p><p class="" style="white-space:pre-wrap;">Over on the Hopical Storm New Blood Stage, the spotlight is on bands destined for bigger things. <a href="https://open.spotify.com/artist/7j9mTouPi4nUYPj5Y95Pu0?si=sFMtsN5XQTqniq53pagR9Q"><span style="text-decoration:underline"><strong>The Machinist</strong></span></a> bring a sophisticated yet brutal approach to modern metalcore, positioning them as a future powerhouse. Meanwhile, <a href="https://open.spotify.com/artist/3ZLJM8TArYs7ux3l9TFRkn?si=oe8sVa3dSmaZGzNnN0Q11w"><span style="text-decoration:underline"><strong>Fortune Teller</strong></span></a> delivers gritty riffs and authentic charisma, exactly the type of talent that Bloodstock champions year after year.</p><p class="" style="white-space:pre-wrap;">Away from the stages, Bloodstock offers an immersive festival experience complete with the <a href="https://www.bloodstock.uk.com/events/boa-2023/venues/intro"><span style="text-decoration:underline">Metal 2 The Masses competition</span></a>, a critical stepping stone for emerging talent. Local events, such as the East Anglia final at Norwich’s The Brickmakers, demonstrate Bloodstock''s commitment to grassroots growth and community.</p><p class="" style="white-space:pre-wrap;">With its dynamic mix of legendary headliners and burgeoning underground artists, alongside dedicated initiatives and a welcoming atmosphere, Bloodstock Open Air 2025 is set to be an essential event for anyone passionate about discovering the future of heavy music.</p><p class="" style="white-space:pre-wrap;">Don''t miss out—grab your tickets now from the <a href="https://bloodstock.seetickets.com/event/bloodstock/catton-park/3131566#op1"><span style="text-decoration:underline">official Bloodstock website</span></a>, or dive into our specially curated ''Ones to Watch'' playlist to discover your new favourite bands.</p></div><iframe style="border-radius:12px" src="https://open.spotify.com/embed/playlist/28Zj8kFDYnHLQc144GiPT0?utm_source=generator" width="100%" height="352" frameBorder="0" allowfullscreen="" allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture" loading="lazy"></iframe>',
  'Bloodstock Open Air 2025 continues its legacy as the heart and soul of British heavy music, set in the scenic grounds of Catton Park, Derbyshire. With a powerful mix of iconic headliners and exciting newcomers, this year''s festival, scheduled for 7th to 10th August, promises a vibrant celebration of',
  'Feats.',
  '2025-04-25 10:00:00',
  'Festival, Line Up Review',
  '/images/articles/480227114_1166097371544839_6881514108013743355_n.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Bulgarelli At New Cross Inn 28.04.2025',
  'bulgarelli-at-new-cross-inn-28-04-2025',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">There aren’t many venues left in London like the <strong>New Cross Inn</strong>. A cornerstone of the grassroots circuit, it’s known for loud nights, affordable drinks, and a stage that’s launched more than a few careers. On Monday 28 April, it played host to five bands covering a wide spectrum of alternative sounds — from punk to post-hardcore to melodic indie — in a stacked and well-paced evening that felt like a proper showcase of where UK DIY music is at.</p></div>

