INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Coco &amp; The Lost Live @ SXSW London 05.06.2025',
  'coco-and-the-lost-live-sxsw-london-05-06-2025',
  '[caption id="" align="alignnone" width="1200"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/5fe0bc2b-74b0-4e15-9180-3fa4326df96e/%40TJEPhotos_+-+Coco+%26+The+Lost+-+Jaguar+Shoes+-+06-06-2025+-+016.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Wrapping Up SXSW London Day 4 we had Coco &amp; the Lost performing an acoustic set at Jaguar Shoes, with an emotional and impactful take on her normal energetic ‘cinematic pop’, she had crisp vocals, and great humour between sets!<br><br>Performing her latest single “Um and Ah”, as well as the track “communicator” touching on struggles with social anxiety away from the stage, a relatable experience for many! Bringing her catalog into an acoustic setting was an enjoyable and touching experience, fully allowing her lyricism to shine through in comparison from her usual energetic and eclectic performances.&nbsp;</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749393847556-WRWP1344KQTNIOC3OHNQ/%40TJEPhotos_+-+Coco+%26+The+Lost+-+Jaguar+Shoes+-+06-06-2025+-+030.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749393847695-4R3HTMCBT6122Z8DFMZV/%40TJEPhotos_+-+Coco+%26+The+Lost+-+Jaguar+Shoes+-+06-06-2025+-+031.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749393849055-4I6TDNV834CZCJFJAWWP/%40TJEPhotos_+-+Coco+%26+The+Lost+-+Jaguar+Shoes+-+06-06-2025+-+032.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749393849125-4UQGOR8XN0Z8RCKEE9IL/%40TJEPhotos_+-+Coco+%26+The+Lost+-+Jaguar+Shoes+-+06-06-2025+-+033.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749393850573-226IGBB3N3RD5GASJO5A/%40TJEPhotos_+-+Coco+%26+The+Lost+-+Jaguar+Shoes+-+06-06-2025+-+034.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749393850549-6OQV0IBDHLK305P1IT3K/%40TJEPhotos_+-+Coco+%26+The+Lost+-+Jaguar+Shoes+-+06-06-2025+-+035.jpg?format=original" />
  

  
