INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Dan Clancy’s “The Live Streaming Economy” @ SXSW London 2025',
  'dan-clancys-the-live-streaming-economy-sxsw-london-2025',
  '[caption id="" align="alignnone" width="1200"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1fd5e2d6-c2ae-4778-9c79-a3df1b019599/%40TJEPhotos_+-+Dan+Clancy+-+Truman+Brewery+-+02-06-2025+-+010.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Dan Clancy Spoke at SXSW London for the first time on Monday, giving a talk titled “The Live Streaming Economy”, in which he introduced what Live streaming is, he talked the audience through the history of Twitch &amp; their early Success, and ultimately spoke about where he see’s the Live streaming world going.</p><p class="" style="white-space:pre-wrap;"><strong>Here’s our main takeaways</strong></p><p class="" style="white-space:pre-wrap;"><span style="text-decoration:underline">In&nbsp;June 2011, </span><a href="http://twitch.tv"><span style="text-decoration:underline">Twitch.tv</span></a> started as “JustinTV”, where Justin, Ken &amp; several other early-day streamers would frequently turn on a camera and stream themselves doing various day-to-day activities. </p></div>


  
       [caption id="" align="alignnone" width="1200"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/3bb65534-4fc5-48ec-a115-814d5fc2e530/%40TJEPhotos_+-+Dan+Clancy+-+Truman+Brewery+-+02-06-2025+-+003.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">In July 2010, StarCraft 2 Released to critical acclaim, the CEO of JustinTV at the time, Emmet Sheer decided to pivot, renaming the company to “Twitch” and exclusively allowing gaming related content, even going as far to implement a “20 minutes policy”, in which anyone that streams anything other than gaming related content for more than 20 minutes would be banned from the site. Dan explained how actions like this, a clear focus on gaming related content, helped to build Twitch into what it is today, creating a strong brand image too. </p><p class="" style="white-space:pre-wrap;">Dan then went on to talk about how the platform has changed over time, in the years following Twitch’s push for gaming related content the platform has started adding more and more categories, he described streamers like Kai Cenat “going full circle”, meaning that instead of having specific gaming related content, they’ve built a career around just being live &amp; entertaining on the platform, with 10,000’s of viewers a day tuning in to witness their streamer, describing streamers&nbsp; “Leaning into Twitch (to) connect directly with their community”.</p></div>


  
       [caption id="" align="alignnone" width="1200"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/a177526f-49f1-4545-b80a-ef6ada6515d9/%40TJEPhotos_+-+Dan+Clancy+-+Truman+Brewery+-+02-06-2025+-+005.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Similarly Dan highlighted artists like Lizzo, who launched her latest album whilst live on twitch, feeding back that she enjoyed having that “instant feedback” - in the same vein, Dan talked about DJ’s on twitch, one of the most viewed categories on the platform, he said “DJ’s are about building a community”, which was why it fit so well on a community focused platform. He didn’t mention it in the talk, but Dan Clancy actually streams on Twitch too, often performing DJ sets or live music covers (@DJClancy999 on Twitch).</p><p class="" style="white-space:pre-wrap;">To conclude his talk he spoke about the future of Twitch &amp; Live streaming in general, he briefly spoke about the use of AI &amp; how he believes that “Technology provides tools to produce content” for creators, describing a Vtuber which was powered by Ai, trained to produce content based off a specific creators style.<br><br>He also briefly spoke about short-form content, saying “TikTok did to YouTube, What YouTube did to TV”, highlighting the disruptive nature that short-form content has forced its way into the mainstream, but highlighting the adaptability that content must have to perform well, the industry is everchanging meaning creators’ content should too. </p><p class="" style="white-space:pre-wrap;"><br>By the end of Dan’s talk, I was left with one big question, “If TikTok did to YouTube, what YouTube did to TV, where does Twitch &amp; Long form Live Streaming content fit in with that?”.</p></div>',
  'Dan Clancy Spoke at SXSW London for the first time on Monday, giving a talk titled “The Live Streaming Economy”, in which he introduced what Livestreaming is, talk the audience through the history of Twitch &amp; their early Success, and ultimately spoke about where he see’s the Livestreaming world ',
  'Feats.',
  '2025-06-09 10:00:00',
  'SXSW London, AI, Technology, Recap, Review',
  '/images/articles/%40TJEPhotos_+-+Dan+Clancy+-+Truman+Brewery+-+02-06-2025+-+010.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Death From Above 1979 Live @ Camden Electric Ballroom 20.07.2025',
  'death-from-above-1979-live-camden-electric-ballroom-20072025',
  '<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/9da93428-9840-4b4c-9cc4-ea686bda2438/%40Unbridledmess+-+Death+From+Above+-+Camden+Electric+Ballroom+-+20-07-2025+-+062.jpg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">After a a long year departure from the UK, Death From Above 1979 have returned for a one-off London show in the legendary Electric Ballroom in Camden, with previous openers and close friends of the band YAANG returning.&nbsp;</p><p class="" style="white-space:pre-wrap;">The night began with a very crowded ballroom, with much of the gig turning up for Yaang, the increasing the energy from the band and crowd; beginning with the very epic and eccentric song ‘Comfort’ making their sound and style known; with heavy riffs, crazy additives like synths and drum tracks that make for a very funky time.&nbsp;</p></div>


  
      <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/0ae6b2a3-da46-410c-96c7-d18b4217a20e/%40Unbridledmess+-+Death+From+Above+-+Camden+Electric+Ballroom+-+20-07-2025+-+073.jpg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">The band absolutely powered through their set exercising their two-steps, their technical ability and impressive compilation of sound to create something abrasive but all groovy all in the same song. If you’re a fan of Death From Above 1979, these guys will certainly be up your alley, they may be lacking a drummer but the three of them prove they don’t need one and then some.</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1753374085662-BFL88S1FAIBK02DLZX1N/%40Unbridledmess+-+Death+From+Above+-+Camden+Electric+Ballroom+-+20-07-2025+-+012.jpg?format=original" />
  

  
