INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Feats. Guide to The Great Escape 2025: Your Next Favourite Artists',
  'feats-guide-to-the-great-escape-2025-your-next-favourite-artists',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Brighton’s <strong>The Great Escape (TGE)</strong> returns in May 2025, transforming the city into a vibrant centre for new music discovery. Over four days, from Wednesday 14th to Saturday 17th May, more than 450 artists will play across numerous venues, ranging from intimate pubs to pop-up stages on Brighton Beach. This annual event has gained a reputation for being the place to spot emerging artists early, in a relaxed but bustling atmosphere.</p><p class="" style="white-space:pre-wrap;">The festival kicks off on <strong>Wednesday 14th May</strong> with a special opening show featuring <strong>Peter Doherty</strong> of The Libertines, setting the stage for an exciting weekend of live performances. Attendees can expect spontaneous sets and unique experiences, particularly during the festival''s late-night ''Alternative Escape'' shows.</p><h3 style="white-space:pre-wrap;"><strong>Previous Highlights from TGE</strong></h3><p class="sqsrte-large" style="white-space:pre-wrap;">Each year, TGE showcases some of the most promising new acts around. In previous editions, Feats. covered standout performances, including<a href="https://feats.live/music/yonakatge"> <span style="text-decoration:underline"><strong>Yonaka’s explosive homecoming show</strong></span></a> in 2023 and<a href="https://feats.live/music/noisy-live-tge"> <span style="text-decoration:underline"><strong>NOISY’s energetic set</strong></span></a>. We also highlighted rising artists like<a href="https://feats.live/music/sad-night-dynamic-tge23"> <span style="text-decoration:underline"><strong>Sad Night Dynamite</strong></span></a> and<a href="https://feats.live/music/hotwaxtge23"> <span style="text-decoration:underline"><strong>HotWax</strong></span></a>, who have continued to attract attention nationwide.</p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><h3 style="white-space:pre-wrap;"><strong>Artists to Watch at TGE 2025</strong></h3><p class="" style="white-space:pre-wrap;">This year''s line-up again features diverse and exciting talent. Brighton locals <a href="https://open.spotify.com/artist/1pQ8qfxpuRJKEUFPGrf6Uc?si=NZUTuDNUSIKuW0-qKTvpNA"><span style="text-decoration:underline"><strong>ARXX</strong></span></a> promise a punchy performance with their punk-rock style, and electro-punk trio <a href="https://open.spotify.com/artist/0y7VykZdOB8wIsAQfr2S4M?si=s9tNw0nATiqB0hIWqxsthQ"><span style="text-decoration:underline"><strong>CLT DRP</strong></span></a> are set to deliver a highly charged set. Other UK-based bands include the gritty <a href="https://open.spotify.com/artist/5YFIVhzlaYH9Yadjw9gSUx?si=jznHvh3HTmmjvzL9vsWmsA"><span style="text-decoration:underline"><strong>James and the Cold Gun</strong></span></a>, teen punk artist <a href="https://open.spotify.com/artist/3uqAKGSytLJJuLy4BPlY38?si=kTI2A8v_RnK_KjdD4KHSGg"><span style="text-decoration:underline"><strong>BEX</strong></span></a>, post-punk favourites <a href="https://open.spotify.com/artist/3oLTaC5QBOH96VbxMAafpZ?si=SANcJIXRRGG_yIf31wcGyA"><span style="text-decoration:underline"><strong>Courting</strong></span></a>, and energetic newcomers <a href="https://open.spotify.com/artist/3DL0niCT8vzd0DQ0AXaLly?si=KmWq9BOJSiitM4ykj5v8MQ"><span style="text-decoration:underline"><strong>The Molotovs</strong></span></a>. Fans of louder music should also look out for raw, energetic acts like <strong>Filthy Pig</strong> and <a href="https://open.spotify.com/artist/5WunDwdY4e0nWZXHOeFLF1?si=oBqRfi7yR1uQUf4eaQ6qUw"><span style="text-decoration:underline"><strong>Black Fondu</strong></span></a>.</p><p class="" style="white-space:pre-wrap;">In pop and electronic genres, duo <a href="https://open.spotify.com/artist/2U6J9Q89i1TNhesKreFD65?si=4Vq7ELSaRH6RLLzoSxxqBA"><span style="text-decoration:underline"><strong>piri &amp; tommy</strong></span></a> will bring their popular blend of drum &amp; bass and catchy pop melodies, while <a href="https://open.spotify.com/artist/4U5QErgn94wZGw1rJz01BO?si=-k7EZFAGTj6KY4jpV7yYjQ"><span style="text-decoration:underline"><strong>Charlotte Plank</strong></span></a> and <a href="https://open.spotify.com/artist/34TRRbxNJYpDV7VJ7kBzQd?si=Vnqfvn2NRb6Bf_nxwRd9eA"><span style="text-decoration:underline"><strong>Sofy</strong> </span></a>offer vibrant indie-pop sets. Audiences should also watch out for the eccentric and theatrical performances of <a href="https://open.spotify.com/artist/44tV2d4RDeMsS2sLOdcXHD?si=3xqpx0pAQaCnuOGmidmbPw"><span style="text-decoration:underline"><strong>LYNKS</strong></span></a>, alongside R&amp;B talents like <a href="https://open.spotify.com/artist/5k6BuuGye7fUjFvPOOJ8C2?si=AxglEzRqQvS995hAfaD9mg"><span style="text-decoration:underline"><strong>Simone</strong></span></a>, and hip-hop artists <a href="https://open.spotify.com/artist/1OyML8UXqmlHP7JHexdJVl?si=C43dreKSRPe0ACfXKVmqTw"><span style="text-decoration:underline"><strong>Silk Ye</strong></span></a>, <a href="https://open.spotify.com/artist/5wNj12LdeLBP40sovnVq2Y?si=E9PYw_7HTtGuq22lBS7Wqw"><span style="text-decoration:underline"><strong>WREX</strong></span></a>, and New Zealand’s genre-fusing rapper <a href="https://open.spotify.com/artist/5QYfFIxVcsJtK600MxqtpF?si=mlGIRncZRHq4uX5hKQ3e7Q"><span style="text-decoration:underline"><strong>Chaii</strong></span></a>.</p><p class="" style="white-space:pre-wrap;">International talent remains a strong focus, with Japan’s funky ensemble <a href="https://open.spotify.com/artist/4S8J8Nct8lHsbzAeNJXcJa?si=CB7ryLdLSny5_FgQkpP8sg"><span style="text-decoration:underline"><strong>Kroi</strong></span></a>, French rock band <a href="https://open.spotify.com/artist/4S47feOS2ATuhc7Ao5ilfG?si=j5fgrWg4TMu9NU-EJLKM9Q"><span style="text-decoration:underline"><strong>Last Train</strong></span></a>, and Finnish alt-metal band <a href="https://open.spotify.com/artist/5OMIs8tNddcCXVDMN8LLyQ?si=_ROmy3OEQXiAlU5gNHc_ag"><span style="text-decoration:underline"><strong>Luna Kills</strong></span></a> making appearances. Legendary British rockers <a href="https://open.spotify.com/artist/5HlXA01kcjssYDT7EoqUJF?si=h1GYAqfRStKGnd6VP3R-dA"><span style="text-decoration:underline"><strong>Skunk Anansie</strong></span></a> are also set to perform, bridging established acts with emerging artists.</p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><h3 style="white-space:pre-wrap;"><strong>Feats Ones to Watch</strong></h3><p class="sqsrte-large" style="white-space:pre-wrap;">Here are five standout artists we particularly recommend catching:</p><ul data-rte-list="default"><li><p class="" style="white-space:pre-wrap;"><a href="https://open.spotify.com/artist/3uuE1sz7PjwnzBKtK2YMEK?si=1K1tWXjATvC43o8sOM9_GQ"><span style="text-decoration:underline"><strong>Lonnie Gunn</strong></span></a> – Brighton-based indie-rock artist known for witty lyrics and engaging melodies, Lonnie Gunn''s live shows are celebrated for their energetic atmosphere and memorable songwriting. She brings a relatable, heartfelt approach to indie music that''s quickly gaining attention.</p></li><li><p class="" style="white-space:pre-wrap;"><a href="https://open.spotify.com/artist/4fB4kEtCb6T9qYNJIeFemW?si=nR-_wVioSw-9rG5TMjunjQ"><span style="text-decoration:underline"><strong>Lowen</strong> </span></a>– Hailing from London, Lowen seamlessly blends elements of doom-rock, folk, and Middle Eastern influences into their powerful soundscapes. Their vocalist’s striking range and haunting performance promise an unforgettable live experience.</p></li><li><p class="" style="white-space:pre-wrap;"><a href="https://open.spotify.com/artist/4Fc4GqcYwYnTePiW3nggrd?si=o57r5ez6SfqvGAHjLe4B_w"><span style="text-decoration:underline"><strong>Mouth Culture</strong></span></a> – This alt-pop outfit from the Midlands is rapidly building a fanbase thanks to their irresistibly catchy choruses and high-energy live performances. Their music is full of youthful exuberance, offering an engaging show perfect for festival crowds.</p></li><li><p class="" style="white-space:pre-wrap;"><a href="https://open.spotify.com/artist/2AOTmilsEJDBEM6SIHFFy6?si=dliMXIbMTVSH-HvGKkCllw"><span style="text-decoration:underline"><strong>Blanket</strong> </span></a>– Known for their expansive, cinematic approach to rock music, Blanket crafts lush, atmospheric soundscapes. Their recent collaboration with Kadeem France of acclaimed band Lothe on the track “In Awe” has further showcased their dynamic range and earned them additional acclaim within the alternative music scene. Expect immersive, emotionally charged live performances driven by intricate musicianship and soaring vocals, making their set a standout experience at TGE 2025.</p><p class="" style="white-space:pre-wrap;"><a href="https://open.spotify.com/artist/5OMIs8tNddcCXVDMN8LLyQ?si=_ROmy3OEQXiAlU5gNHc_ag"><span style="text-decoration:underline"><strong>Luna Kills</strong></span></a> – Flying in from Finland, Luna Kills offer a dynamic blend of alt-metal, electronic elements, and raw intensity. Fronted by a commanding vocalist, their energetic performances and powerful stage presence are sure to ignite audiences and leave a lasting impression.</p></li></ul><h3 style="white-space:pre-wrap;"><strong>Get Ready for TGE 2025</strong></h3><p class="" style="white-space:pre-wrap;">Revisit previous festival coverage and artist interviews from TGE 2023 on the<a href="https://www.youtube.com/@FeatsLive/videos"> <span style="text-decoration:underline">Feats. YouTube channel</span></a>.</p><p class="" style="white-space:pre-wrap;">To help prepare for the festival, we''ve curated a special <strong>TGE 2025 Playlist</strong> featuring many of the highlighted artists.</p><p class="" style="white-space:pre-wrap;"><a href="https://open.spotify.com/playlist/22vdCrzDjvltp87N4dLYbj?si=c67bb40093f94a19"><span style="text-decoration:underline">Listen on Spotify</span></a> and start planning your festival schedule. Enjoy discovering your new favourite artists!</p></div><iframe style="border-radius:12px" src="https://open.spotify.com/embed/playlist/22vdCrzDjvltp87N4dLYbj?utm_source=generator" width="100%" height="352" frameBorder="0" allowfullscreen="" allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture" loading="lazy"></iframe>',
  'Brighton’s The Great Escape (TGE) returns in May 2025, transforming the city into a vibrant centre for new music discovery. Over four days, from Wednesday 14th to Saturday 17th May, more than 450 artists will play across numerous venues, ranging from intimate pubs to pop-up stages on Brighton Beach.',
  'Feats.',
  '2025-04-28 10:00:00',
  'THE GREAT ESCAPE, Festival, Line Up Review',
  '',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Feats. Ones-to-Watch 2025 Festival Round Up',
  'feats-ones-to-watch-2025-festival-round-up',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Every year, a handful of artists break through the festival season with sets that spark conversations long after the fields empty. Some are already on the rise, others are just getting started, but all have shown why they deserve a spot on your radar. Here are five acts that caught attention across the UK this summer - and where you can see them next.</p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><h3 style="white-space:pre-wrap;">HotWax - Latitude and Victorious</h3></div>


  
       [caption id="" align="alignnone" width="5427"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/894e7b8d-31be-45f0-816c-d2c61d95dc4f/DSC08890.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><a href="https://open.spotify.com/artist/237mvWGlQNJJhc9b8pSawZ?si=79fqh78MS5SdeOSPZO7R-Q"><span style="text-decoration:underline"><strong>HotWax </strong></span></a>continue to establish themselves as one of the most exciting new guitar bands in the UK. Their mix of grunge, punk and sharp hooks was on full display this summer, with appearances at <a href="https://www.latitudefestival.com/"><span style="text-decoration:underline"><strong>Latitude</strong> </span></a>and <a href="https://www.victoriousfestival.co.uk/"><span style="text-decoration:underline"><strong>Victorious</strong> </span></a>pulling in strong reactions from crowds. Songs like <a href="https://open.spotify.com/track/7vcgqskkBA3n2aykT0AjUJ?si=a73815afb8eb4f20"><span style="text-decoration:underline"><em>Treasure</em> </span></a>and <a href="https://open.spotify.com/track/0jRFTDwXR7FygEqRHyju8P?si=05f92e6fa38243de"><span style="text-decoration:underline"><em>Rip It Out</em> </span></a>proved popular talking points, with fans highlighting the energy and urgency of their live shows.</p><p class="" style="white-space:pre-wrap;">We caught up with HotWax ahead of their Latitude performance to talk about their debut album and life on tour with Nova Twins - <a href="https://feats.live/music/hotwax-talk-debut-album-amp-nova-twins-tour-before-their-latitude-2025-set"><span style="text-decoration:underline">you can read the full interview here.</span></a></p><p class="" style="white-space:pre-wrap;"><a href="https://www.bandsintown.com/a/935183-hotwax"><span style="text-decoration:underline"><strong>Next up:</strong> <strong>O2 Forum Kentish Town, London, Sat 18 Oct</strong>.</span></a></p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><h3 style="white-space:pre-wrap;">Lola Young - Glastonbury</h3></div>


  
      <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/2b64cf3d-7093-4a71-afcb-939dc2bbf8cf/Lola+Young.webp?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Blending confessional songwriting with alt-pop polish, <a href="https://open.spotify.com/artist/67FB4n52MgexGQIG8s0yUH?si=F_t2smqXRPmyrQJ7mjXCvg"><span style="text-decoration:underline"><strong>Lola Young </strong></span></a>brought her distinctive voice to the <strong>Park Stage at </strong><a href="https://www.glastonburyfestivals.co.uk/"><span style="text-decoration:underline"><strong>Glastonbury</strong> </span></a>this summer. Fans said her set stood out for its openness, with tracks like <a href="https://open.spotify.com/track/35ISBknsCeZQtq66xABI9g?si=c15e06dc4a194d83"><span style="text-decoration:underline"><em>Messy</em> </span></a>resonating strongly and being shared widely online afterwards. It was another step in a growing career that balances vulnerability with power.</p><p class="" style="white-space:pre-wrap;"><a href="https://www.bandsintown.com/a/13596053-lola-young"><span style="text-decoration:underline"><strong>On tour:</strong> <strong>15 Sept – The Level, Nottingham</strong>, <strong>17 Sept – Pryzm, Kingston</strong>, with more UK dates through October.</span></a></p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><h3 style="white-space:pre-wrap;">VLURE - Reading and Leeds</h3></div>


  
      <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/0b765e51-86b3-4a88-acd8-42e6ae6de80a/VLure.jpeg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Glasgow’s <a href="https://open.spotify.com/artist/0Ev1tqYsfzq2eF5qqXhkYm?si=yNch4r8BSSeX5WKvUQg67w"><span style="text-decoration:underline"><strong>VLURE</strong> </span></a>have been on our radar for a while. Back in 2023, we followed them through the release of <a href="https://open.spotify.com/album/0KO5XrMKrkHGyAhjJknWP4?si=pYe64vz_RRCAmujuaFSK9Q"><span style="text-decoration:underline"><em>Cut It</em> </span></a>and spoke about their ability to merge the emotion of post-punk with the physicality of club music (<a href="https://feats.live/music/vlure-set-us-free-as-we-follow-them-through-the-release-of-their-new-single-cut-itnbsp"><span style="text-decoration:underline">Read Our Original Article Here</span></a>). That same mix has only grown stronger.</p><p class="" style="white-space:pre-wrap;">This summer they brought their electronic-punk energy to <a href="https://www.readingfestival.com/"><span style="text-decoration:underline"><strong>Reading</strong> </span></a>and <a href="https://www.leedsfestival.com/"><span style="text-decoration:underline"><strong>Leeds</strong></span></a>, with crowds responding to the intensity of tracks that move between raw vulnerability and euphoric release. Fans described the shows as moments of catharsis - heavy, emotional, but built to move.</p><p class="" style="white-space:pre-wrap;"><a href="https://www.bandsintown.com/a/15488327-vlure"><span style="text-decoration:underline"><strong>Upcoming dates:</strong> Rough Trade in-stores across the UK in late September, followed by a run of shows in October and November including London’s Fabric, Newcastle’s The Grove and European stops in Paris, Milan, Berlin and Brussels.</span></a></p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><h3 style="white-space:pre-wrap;">Nxdia - Reading and Leeds</h3></div>


  
      <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/ac3bbb8b-3d42-4fd3-b770-a19f64a30443/Nxdia.jpeg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Manchester’s <a href="https://open.spotify.com/artist/0Dkj3iE06TJGxGIrGCmwVf?si=Vqplt1clQQ6XgKwuMY2ZJA"><span style="text-decoration:underline"><strong>Nxdia</strong> </span></a>combined alt-pop melodies with punk spirit at both <a href="https://www.readingfestival.com/"><span style="text-decoration:underline"><strong>Reading</strong> </span></a>and <a href="https://www.leedsfestival.com/"><span style="text-decoration:underline"><strong>Leeds</strong></span></a>, drawing strong reactions across the weekend. Songs like <a href="https://open.spotify.com/track/7nuCxvFvVT5YEAjSDd6Glr?si=794f309b121a4c7f"><span style="text-decoration:underline"><em>Boy Clothes</em> </span></a>and <a href="https://open.spotify.com/track/062xVECDI7YZqOgdEtWlVs?si=003077780c704704"><span style="text-decoration:underline"><em>She Likes a Boy</em> </span></a>became instant singalongs, with fans praising the sense of inclusivity and openness that shaped the sets. For many, it was a first introduction that quickly turned into a highlight.</p><p class="" style="white-space:pre-wrap;"><a href="https://www.bandsintown.com/a/15556752-nxdia"><span style="text-decoration:underline"><strong>Tour dates:</strong> <strong>5 Oct – The Lodge, Manchester</strong>, <strong>6 Oct – King Tuts, Glasgow</strong>.</span></a></p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><h3 style="white-space:pre-wrap;">Flowerovlove -&nbsp; Latitude, Tramlines, Standon Calling, Camp Bestival</h3></div>


  
      <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/70050a31-75a8-4cdb-8db1-2219efea48c4/Flowerovlove.webp?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><a href="https://open.spotify.com/artist/1JspXUvEv3D9ddMeLNqYWj?si=AwwCkIUFS0uEJPQeNG6_Gw"><span style="text-decoration:underline"><strong>Flowerovlove</strong> </span></a>(Joyce Cissé) brought bright, melodic indie-pop to a busy festival summer with appearances at <a href="https://www.latitudefestival.com/"><span style="text-decoration:underline"><strong>Latitude</strong></span></a>, <a href="https://tramlines.org.uk/"><span style="text-decoration:underline"><strong>Tramlines</strong></span></a>, <a href="https://www.facebook.com/standoncalling/?locale=en_GB"><span style="text-decoration:underline"><strong>Standon Calling</strong></span></a> and <a href="https://dorset.campbestival.net/"><span style="text-decoration:underline"><strong>Camp Bestival</strong></span></a>. Her shows leaned on warmth and accessibility, with songs like <a href="https://open.spotify.com/track/7lTWrTbrL3BFcc2UZRMSzy?si=a2f098b87c244b0c"><span style="text-decoration:underline"><em>Love You</em></span></a> and <a href="https://open.spotify.com/track/40tZTQ47XEMg7KT61xAEOI?si=a6a33cab2e9b4788"><span style="text-decoration:underline"><em>Coffee Shop</em></span></a> drawing positive reactions from fans online and on site. That balance of energy and calm has made her one of the most talked-about young names on the circuit.</p><p class="" style="white-space:pre-wrap;"><strong>What’s next:</strong> More UK live shows are expected following her summer run.</p></div><hr /><iframe data-testid="embed-iframe" style="border-radius:12px" src="https://open.spotify.com/embed/playlist/1Vwj87K1JJ3r93f43h1yD4?utm_source=generator" width="100%" height="352" frameBorder="0" allowfullscreen="" allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture" loading="lazy"></iframe><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">HotWax, Lola Young, VLURE, Nxdia and Flowerovlove all picked up momentum this summer, with performances that stood out across the UK festival season. Their upcoming dates are the next chance to catch them before they move onto bigger stages.</p></div>',
  'Every year, a handful of artists break through the festival season with sets that spark conversations long after the fields empty. Some are already on the rise, others are just getting started, but all have shown why they deserve a spot on your radar. Here are five acts that caught attention across ',
  'Feats.',
  '2025-09-01 14:00:00',
  'ONES TO WATCH, Festival, Round Up, Editoral',
  '/images/articles/DSC08890.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'February Releases We Think You Should Check Out - FEATS FEBRUARY FEATURE',
  'february-releases-we-think-you-should-check-out-feats-february-feature',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><strong><em>Lost - Linkin park (Single) 10th </em>Feb</strong></p></div>


  
       [caption id="" align="alignnone" width="2160"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/21783594-6126-4318-8e81-b8201cd33b1c/3GrX4W7b%5B35%5D.jpeg?format=original" alt=" James Minchin (Official Press Shot) "/>  James Minchin (Official Press Shot) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Linkin park released their first fully mixed and mastered single since the bands <em>One More Light </em>release in 2017. Lost is a track re-discovered from the archives of their second album, Meteora during the preparation for its re-release in April.&nbsp;This single sonically sits with songs such as “Breaking the Habit” and “Numb” whilst dealing with lyrical themes of feeling lost in memories of trauma to the point of feeling smaller and belittled by them. All performed with Chester Bennington’s Powerful yet Venerable Vocals on top of a simple but heartfelt instrumental.</p><p class="" style="white-space:pre-wrap;">More to come on Feats about the bands journey through rediscovery and what the future holds for Linkin Park </p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><p class="" style="white-space:pre-wrap;"><strong>Let Her Burn - Rebecca Black (Debut Album) 9th Feb</strong></p></div>


  
       [caption id="" align="alignnone" width="2048"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/b0b1bc35-836b-4075-b5c5-16b7da11b834/DSC05844.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Rebecca Black is truly an Icon, covering her show at Brighton’s The Great Escape festival, she proved she is more than a youtube one hit wonder. Releasing her debut album exactly 12 years after, The viral sensation that was “Friday”. If you were expecting a hyper-pop album from her then you may be disappointed. There are hints of hyper-pop but <em>Let Her Burn</em> is definitely a pop album through and through. This album sounds more refined than her previous work, her musicianship is strong and many of the tracks are truly impressive.</p><p class="" style="white-space:pre-wrap;"><em>‘Misery loves company’ </em>takes a slower beat explaining how loneliness can manifest within while ‘<em>Crumbs’ </em>is definitely more of a good girl gone wild track, for those slightly more seductive moments it''s perfect, it feels intimate and produced beautifully!</p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><p class="" style="white-space:pre-wrap;"><strong><em>Call Me What You Like - Lovejoy (Single) 10th </em>Feb</strong></p></div>


  
       [caption id="" align="alignnone" width="3934"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/756be861-0007-445e-9895-159bdd347367/LoveJoy+%2815+of+35%29.jpg?format=original" alt=" Louis Hitchcock (Louishitchphotos/FEATS) "/>  Louis Hitchcock (Louishitchphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">After the Popular release of their sophomore EP ‘<em>PebbleBrain’, </em>Lovejoy have released their newest single,<em> Call Me What You Like, </em>is<em> </em>more explosive than their usual work. This track takes you on a journey, with a chorus that will slap you in the face and production that will blow your mind. It''s exciting to see this band develop and evolve. Hinting at a release of an album, we’re left to wonder if Call Me What You Like will make an appearance, and what direction the album is headed in. Nothing has been confirmed as of yet so we’re all left to see what this band has in store!</p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><p class="" style="white-space:pre-wrap;"><strong>Cassyette - BOOM(Single) 22nd Feb</strong></p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/b651b33d-3c22-42d5-b219-ea35f0e71b6e/DSC00093.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Cassyette has jumped back into the scene with her most recent release, BOOM, after being debuted on her uk tour back in September we have all been patiently waiting for this powerful track to come out, blurring the lines between pop and nu metal, this is a single that she said she wrote ‘while in manic episode, experiencing all the highs and lows’. BOOM replicates this feeling perfectly as this is the perfect song to listen to while in a frenzy.</p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><p class="" style="white-space:pre-wrap;"><strong><em>This is Why - Paramore (Album) 10th </em>Feb</strong></p></div>


  
       [caption id="" align="alignnone" width="2499"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/979bd809-67b4-4006-9354-de0250cec786/PARAMORE_PRESS_11.jpg?format=original" alt=" Atlantic Records (Official Press Shot) "/>  Atlantic Records (Official Press Shot) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Paramore released their first full album since <em>Hard Times </em>in 2017. The 10 track collection sees the band sonically more mature and mellowed out from their original pop punk roots but still retaining their attitude and passive aggressiveness.&nbsp;</p><p class="" style="white-space:pre-wrap;">An album full of bangers, it shows old timers that Paramore are more relevant than ever before and still know how to make great catchy bangers. This album, however, is definitely headed in a more pop direction than before, this is far from a criticism but it will surprise those who are expecting something akin to an old Paramore album. That''s exactly the point though, they have matured and their music has too.</p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><p class="" style="white-space:pre-wrap;"><strong><em>Be On Your Way - Daughter (Single) 8th </em>Feb</strong></p></div>


  
       [caption id="" align="alignnone" width="960"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/98032326-fec1-41a6-b536-41c5792266b9/daughter-960x540.jpeg?format=original" alt=" 4AD ltd (Official Press Shot) "/>  4AD ltd (Official Press Shot) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Daughter returned with their first independent release in 7 years. Be On Your away is a beautiful atmospheric ballad about letting go of a relationship that isn’t working out, despite how hard it is. The layering of lead singer Elena Tonras'' vocals intertwined with delicate violins and powerful drums on the backbeat. This track is sure to make you retrospect on your life at the back of the bus </p><p class="" style="white-space:pre-wrap;"><br><strong><em>Truth Decay - YMAS (Album) 10th </em>Feb</strong></p></div>


  
       [caption id="" align="alignnone" width="2768"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/841ae24a-0a38-407b-9ca7-e93e07d688e9/DSC01240_1.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">You Me at Six follow up their massive 7 album catalogue with the new release, Truth Decay. A band like You Me At Six have proved time and time again that they can do it all. Truth Decay is an Excellent example of why this band is so well loved, From the nostalgic pop punk anthem “God bless the 90’s Kids” to the Heavier “No future? Yeah right!” featuring Enter Shikari’s Rou Reynolds with a massive chorus. This release is full of tracks for the playlist! ‘Deep cuts’ especially is a staple for me, a prominent drum beat, catchy lyrics focusing more on their heavier music with hints of metal screams here and there! </p><p class="" style="white-space:pre-wrap;">We had the pleasure of covering their show at Alexandra Palace, stay tuned for a full album review soon</p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><p class="" style="white-space:pre-wrap;"><strong><em>It Hurts - Enter Shikari (Single) 9th </em>Feb</strong></p></div>


  
       [caption id="" align="alignnone" width="2514"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/3db85a9d-dc38-42bc-beee-fc54798acbb7/Enter-Shikari_Jamie-Waters_Jan2023_1-small_2023-01-11-161449.png?format=original" alt=" Jamie Waters (JAW/Official Press Shot) "/>  Jamie Waters (JAW/Official Press Shot) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><em>It Hurts</em> is Enter Shikari’s newest single for their April 21st Release, A Kiss for the Whole World. Following from their critically acclaimed concept album “Nothing is True and Everything is Possible” the band have a lot to follow up to.&nbsp;</p><p class="" style="white-space:pre-wrap;">With Its hurts being popular with fans and rightfully so, heavy guitar tones and crazy synth production bring to life Shikari''s Signature sound in a refreshing new way. We couldn’t be looking forward to their new release later this year.</p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><p class="" style="white-space:pre-wrap;"><strong><em>Ashnikko - You Make Me Sick (Single)/10th </em>Feb</strong></p></div>


  
       [caption id="" align="alignnone" width="2499"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/9ebc7652-b377-4407-8311-6cb35a3d7301/MECHA+PRESS_0.jpg?format=original" alt=" Vasso Vu (Official Press Shot) "/>  Vasso Vu (Official Press Shot) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Ashnikko released <em>You Make Me Sick</em>, a single that is unashamedly Ashnikko. If you like their other music then we would really recommend this track. Filled with their rash vocals, a dirty backbeat and lyrics that will make you hate the world, this would be a perfect song for any fans of her previous work. It ramps her style that we all know her for to 150%.&nbsp;</p><p class="" style="white-space:pre-wrap;">Personally, I feel that this track fails to go anywhere and doesn’t show much depth. The sound is great and the instrumental is beautifully harsh but it just gets repetitive as the song progresses. So if you love her discography, this is perfect for you. However, if their usual work isn''t for you, I would give this one a miss. </p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><p class="" style="white-space:pre-wrap;"><strong>Check out the playlist here!</strong></p></div><iframe style="border-radius:12px" src="https://open.spotify.com/embed/playlist/6unMscKPuuVf73PNQohnpr?utm_source=generator&theme=0" width="100%" height="352" frameBorder="0" allowfullscreen="" allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture" loading="lazy"></iframe><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><br></p></div>',
  'We cover our music favourite releases from February ',
  'Feats.',
  '2023-03-06 15:00:00',
  'Release Radar, Feats Feature, Review',
  '/images/articles/3GrX4W7b%5B35%5D.jpeg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Final Dose @ Voodoo Daddy’s Showroom 05.06.2025',
  'final-dose-voodoo-daddys-showroom-05-06-2025',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">The opening act, 2nd location, got the crowds energy raised right from the get go. Although missing most of their set I was able to experience their last couple songs, learning that this was in fact their third ever gig - a massive feat and something unexpected from a band with seemingly so much comfort and control being on a stage.&nbsp;</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499165618-VYOG3CK5A1ENKZRE0Y4U/%40shardsoflight_+-+birdwitch+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+006.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499165647-B71IA8S5U56VV84S2396/%40shardsoflight_+-+birdwitch+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+007.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499166731-S32DAV5V2YU7TMRB033R/%40shardsoflight_+-+birdwitch+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+008.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499166772-JE1ISZKU7TNEW0194IVV/%40shardsoflight_+-+birdwitch+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+001.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499168026-137E9C9ZSMPIK6Z67TYA/%40shardsoflight_+-+birdwitch+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+002.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499168292-IGN928837XX31C45U0AH/%40shardsoflight_+-+birdwitch+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+003.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499169208-4ZCT6FVNHBLGEWOAROAD/%40shardsoflight_+-+birdwitch+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+004.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499169424-D3UC7C94EZ627DU4GG6Q/%40shardsoflight_+-+birdwitch+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+005.jpg?format=original" />
  

</div>
<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">The second support, Birdwitch, came with equally as strong stage presence; bashing out 6 original songs despite only having 1 song available for streaming. The singer pouring everything into each and every song, both vocally and physically, alongside brief stories about them too.&nbsp;</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499216202-OOUSKWSWSAVAOOU2O7GQ/%40shardsoflight_+-+final+dose+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+003.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499216236-3ZP0ZK9QQMT3NTD6L1O1/%40shardsoflight_+-+final+dose+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+004.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499217429-9EM7KY36SPHDB5RB6SQ6/%40shardsoflight_+-+final+dose+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+005.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499217476-O77ZHF25P5EBE14ALXOZ/%40shardsoflight_+-+final+dose+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+006.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499218546-A048SAKZTT1JA9QL0BQQ/%40shardsoflight_+-+final+dose+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+007.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499218725-SLX6LIABTVLC6VO5W6FM/%40shardsoflight_+-+final+dose+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+008.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499219923-M3N648VXHWPRB5X3YQQM/%40shardsoflight_+-+final+dose+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+009.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499220021-Z5QGI2FACTVSQUHOPCBZ/%40shardsoflight_+-+final+dose+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+001.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749499221088-DD96GGMLQNQR1UNZIII8/%40shardsoflight_+-+final+dose+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+002.jpg?format=original" />
  

</div>
<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Then came Final Dose, whose stage presence and unique set certainly caught my attention; with the main vocalist arriving on stage with what seemed to be a bag over his head with eye holes. If this wasn’t enough their set boasted the use of very dim red lighting exclusively, paired with a smoke machine, to create an eerie atmosphere that paired wonderfully with their music and caused an interesting dynamic compared to the usual array of different lighting used by most artists.</p></div>',
  'Then came Final Dose, whose stage presence and unique set certainly caught my attention; with the main vocalist arriving on stage with what seemed to be a bag over his head with eye holes. If this wasn’t enough their set boasted the use of very dim red lighting exclusively, paired with a smoke machi',
  'Feats.',
  '2025-06-11 10:00:00',
  'Live Music, Gig Review',
  '/images/articles/%40shardsoflight_+-+birdwitch+-+Voodoo+Daddys+Showroom+-+05.06.2025+-+006.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  '2000 TREES: Bullet For My Valentine Rock The MainStage - Friday at 2000 TREES',
  'friday-at-2000trees-2023',
  '[caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/21b045c2-d129-4da6-ab1e-393f8d2d904b/DSC01502.jpg?format=original" alt="  Tom Ellis (TJEphotos/Feats.live)  "/>   Tom Ellis (TJEphotos/Feats.live)  [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">British rock quartet, Mallavora kicked off our Friday back at Cheltenham Forest during 2000Trees. A band that do not shy away from talking about prevalent issues within our wider world and scene, from sexism and the lack of female headliners/representation, to racism and the lack of diversity in the scene. </p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/051d362d-ffb9-48d3-8d85-16b0810ba64e/DSC09148.jpg?format=original" alt="  Tom Ellis (TJEphotos/Feats.live)  "/>   Tom Ellis (TJEphotos/Feats.live)  [/caption] 
  




  
      <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/16755bdb-cb6d-4145-93b8-f75295804920/DSC09166_1.jpg?format=original" alt=""/>
  




  
      <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/cb6e1989-87e5-4ede-a5ff-0a5a05813df4/carparkTREES20.JPG?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Carpark will bring back the 90’s nostalgia that you’re missing out on, the indie-rock trio, Hattie, Scottie &amp; Loda recreate the music you wished you had growing up.They’re such a fun band live, they create music that is great to dance to, they are definitely on our radar and have been pushing the boundaries, they don’t follow trends, they’ve set out to exactly who they are and make music that’s well worth listening to! </p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/030bc63c-d780-4705-ba95-791c4b06a838/DSC09394_1.jpg?format=original" alt="  Tom Ellis (TJEphotos/Feats.live)  "/>   Tom Ellis (TJEphotos/Feats.live)  [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">We headed to the forest with a well needed rest for the atmospheric Beetlebug, Auri (vocalist) joined onstage with their ukulele, performed to a full forest. The trees surrounded the stage creating an enchanted environment with their Lullaby-esque songs, she may be the sweetest person ever! Soothing melodies and the shining sun beaming down at 2000 Trees, Beetlebug encaptured everyone watching seamlessly.</p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/bcb65ca2-5363-449f-8678-cb21b748a6a0/DSC00133-2.jpg?format=original" alt="  Tom Ellis (TJEphotos/Feats.live)  "/>   Tom Ellis (TJEphotos/Feats.live)  [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">The Brighton based, The XCERTS return to live shows at 2000 trees, with their recent release BLAME, a quintessential XCERTS track, Their revival was incredible, they packed out the Axiom stage, side to side. They looked like they were loving it, and the crowd were in awe the whole time. ‘Feels like falling in love’ and ‘Ache’ were screamed back at the band, they played ache twice the second rendition had the crowd singing at them, a beautiful moment to frame their return!</p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/b656809d-34f9-4670-975c-7229d94f98ff/DSC00539_1.jpg?format=original" alt="  Tom Ellis (TJEphotos/Feats.live)  "/>   Tom Ellis (TJEphotos/Feats.live)  [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Empire State bastards, Simon Neil’s (of Biffy Clyro) most recent endeavour with Mike Vennart, saw his vocals utilised on ways you would never expect, if you’re a fan of Biffy Clyro then I don’t think this will be your ideal cup of tea. Theatrical and intense brewed insanity within Simon Neil and the crowd, screams echoed through with this new death metal band. Anticipation and expectations buzzed around about Empire State Bastards, with no one expecting death metal and a performance that was almost opposite from one of Biffy Clyro. Simon Neil gas proved time and time again that he can do anything, a musical genius is putting it lightly. </p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/e3ebb133-29cd-438f-a893-fc831d881971/DSC00845.jpg?format=original" alt="  Tom Ellis (TJEphotos/Feats.live)  "/>   Tom Ellis (TJEphotos/Feats.live)  [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><br><br><br>The stacked day was then Topped by Welsh Rock legends Bullet for my Valentine. As they took to the stage the crowd roared with excitement and anticipation and they did not disappoint. A set decorated by fan favourites such as ‘Your Betrayal’ and ‘Over It’ swell as  the brief reprise of Lead singer Matt Tuck’s previous project ‘Axe Wound’ alongside Liam Corimer of Cancer Bats. The set then came to a close with the infamous ‘Tears don’t Fall’ as the entire cotsworld forest chanted their childhood anthem, then followed by ‘Waking the demon’, where the fields became a war zone of circle pits and dust. A perfect ending to the penultimate day. </p></div>


  
       [caption id="" align="alignnone" width="6000"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/ea14f497-4d2f-4405-9f8d-2906bcf23a89/BULLET+1+ARTICLE.JPG?format=original" alt="  Sophie Bingham (DisplacedImages/Feats.live)  "/>   Sophie Bingham (DisplacedImages/Feats.live)  [/caption]',
  'Bullet For My Valentine headlined the Friday night at 2000 Trees 2023, joined by the return of Xcerts, indie-rock-poppers Carpark, &amp; so many more on this stacked bill!',
  'Feats.',
  '2023-07-21 12:03:17',
  'Festival, Gig Review',
  '/images/articles/DSC01502.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Friday Highlights at The Great Escape 23',
  'friday-at-tge',
  '[caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/d313b566-45db-41d1-9510-3457f5df94aa/DSC01454_1.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">The day kicked off with a slightly more tired energy than the previous day, however Noisy DJ set got us energised and ready for the day.&nbsp;</p><p class="" style="white-space:pre-wrap;">Even though the day ended up with me seeing less bands than anticipated, it has by far been my favourite day.</p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/fcdfd9c1-f507-47e2-8d9d-2a660b5efe6c/DSC01545.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><br>Our first visit to Club Revenge was to see Lizzie Esau delivered an electric set to an absolutely packed out room. We then set on our way to see shrimp eyes play at shortts bar and they exceeded expectations. As the band set to start their set the small Brighton venue filled up with fans and anticipators alike. Straight from Shortts we headed to an AWAL mixer at the Brighton dome as Alice Longyu Gao who was looking extra superstar at the event.&nbsp;</p></div>


  
       [caption id="" align="alignnone" width="7008"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/4d3cc99e-4717-4d8b-9c63-c632fe00ef41/Vlure+28.03.23+%2825+of+43%29.jpg?format=original" alt=" Louis Hitchcock (LouisHitchPhotos/FEATS) "/>  Louis Hitchcock (LouisHitchPhotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">As golden hour kicked in VLURE took to the PIAS stage at the Charles St Tap, to deliver yet another magnificent performance.they set the tone for my friday night rave vibe with their trademark KLF inspired punk euphoric beat.&nbsp;</p><p class="" style="white-space:pre-wrap;">The start of a back to back at club revenge was Jessica Winter. Taking to the stage wearing another one of her iconic Power suits, the set began with her seductive black leather finger clicking. Carrying on the sultry energy throughout the set, the opening track of Limerence “Choreograph” provided a gorgeous ending to another theatrical performance celebrating queer identity.&nbsp;</p><p class="" style="white-space:pre-wrap;">Next up, Bristolian producer Grove blasted through their third and final set of the weekend. Referencing everything from the French Revolution to calling out immoral landlords and the outdated Monarchy system. Followed by a rare moment of openness Grove introduced accomplished visual and audio artiste EJ Akin as their romantic partner alongside being their stage partner.&nbsp;</p></div>


  
       [caption id="" align="alignnone" width="4608"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/499d1bb1-e7f1-459e-bbe9-0461c54ca041/The+Great+Escape+2023-35.jpg?format=original" alt=" Louis Hitchcock (LouisHitchPhotos/FEATS) "/>  Louis Hitchcock (LouisHitchPhotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">We had the chance to catch up with Yonaka, who recently released two new singles teasing their newest EP: Welcome To My House. A band who will bring the energy while making you cry two songs later.<br><br>In a true celebration of fangirl culture and wrapping up the second day of this year’s Great Escape, politically charged Deadletter stormed through an exhilarating rousing set that started at 2 AM at Chalk. Deadletter delivered a set that consisted of post punk realness that I had hoped and wished for to end off the night.&nbsp;Making the crowd Romp through the early hours of the night.</p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><p class="" style="white-space:pre-wrap;">Up next for today’s line up are the brilliant rap trio FrozeMode alongside one of the headliners, Arlo Parks and indie band Gengahr.&nbsp;</p><p class="" style="white-space:pre-wrap;"><br><br><br><br></p></div>',
  'Our Highlights from Friday at Brighton’s Great Escape!',
  'Feats.',
  '2023-05-13 11:28:02',
  'Festival, Highlights, THE GREAT ESCAPE',
  '/images/articles/DSC01454_1.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'From Gigs to Reels: How Artists Are Adapting to the Cinematic Trend',
  'from-gigs-to-reels-how-artists-are-adapting-to-the-cinematic-trend',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">The music industry has always been dynamic, continuously reshaped by evolving consumer preferences, technological advancements, and strategic business innovations. Recently, an intriguing trend gaining momentum is the transformation of live music tours into cinematic experiences. While this trend is prominent among established mainstream acts, it presents significant challenges for smaller and emerging artists who face increased expectations and financial burdens.</p><p class="" style="white-space:pre-wrap;">A notable example among smaller artists navigating this landscape is Australian indie musician <a href="https://open.spotify.com/artist/4OOlG5eBXSkSAAEeKjJb5Y"><span style="text-decoration:underline">Courtney Barnett</span></a>, who released her film "<a href="https://www.anonymousclubfilm.com/"><span style="text-decoration:underline">Anonymous Club</span></a>" in 2022. This intimate, documentary-style film provides fans with a candid glimpse into Barnett''s artistic process, touring life, and personal reflections, resonating deeply due to its authenticity and emotional depth. Unlike larger blockbuster releases such as <a href="https://open.spotify.com/artist/06HL4z0CvFAxyc27GXpf02"><span style="text-decoration:underline">Taylor Swift’s</span></a> "<a href="https://www.youtube.com/watch?v=KudedLV0tP0"><span style="text-decoration:underline">The Eras Tour</span></a>", Barnett''s film relies heavily on storytelling and genuine vulnerability rather than extravagant production values. Even so, achieving the necessary production standards remains financially demanding and logistically challenging for independent artists.</p><p class="" style="white-space:pre-wrap;">Concert films have historical roots dating back several decades, exemplified by iconic releases such as <a href="https://open.spotify.com/artist/2x9SpqnPi8rlE9pjHBwmSC"><span style="text-decoration:underline">Talking Heads</span></a>'' "<a href="https://www.youtube.com/watch?v=-rjMwSTeVeo"><span style="text-decoration:underline">Stop Making Sense</span></a>," directed by Jonathan Demme and recently re-released to critical acclaim. Premiering originally in 1984, this film was praised for its innovative approach and ability to capture the vibrant energy of live performances. Such historical examples underline how concert films have long been a valuable artistic medium and commercial strategy, though their prominence and required production standards have increased significantly over time.</p><p class="" style="white-space:pre-wrap;">In recent years, artists across various genres and audience sizes, including renowned alternative musician <a href="https://open.spotify.com/artist/4UXJsSlnKd7ltsrHebV79Q"><span style="text-decoration:underline">Nick Cave</span></a> with "<a href="https://www.youtube.com/watch?v=IGn0V6A1uP8"><span style="text-decoration:underline">Live at Alexandra Palace</span></a>", have embraced the concert film format. Cave’s film demonstrates the medium''s potential to create immersive experiences, yet simultaneously highlights the disparity in resources available to established versus emerging artists. Smaller artists are compelled to meet high industry expectations regarding production quality, visuals, and sound design, placing considerable strain on their limited budgets and resources.</p><p class="" style="white-space:pre-wrap;">Consequently, smaller and emerging artists increasingly struggle to gain traction without significant financial support. Rising costs associated with professional-grade media production, distribution, and sophisticated marketing strategies create substantial barriers to entry. As larger artists set higher standards through cinematic releases, independent musicians face intense pressure to match these expectations to remain competitive. Far from being universally accessible, concert films represent a substantial investment that smaller artists often find challenging to justify, despite the potential for increased visibility.</p><p class="" style="white-space:pre-wrap;">Several factors contribute significantly to the overall popularity of concert films. Technological advancements have greatly enhanced the quality of media production, making cinema-grade audio-visual experiences possible but also raising audience expectations considerably. Audiences now anticipate polished visuals, impeccable sound mixing, and engaging visual narratives, which can surpass traditional live concert experiences.</p><p class="" style="white-space:pre-wrap;">Economic factors also influence this trend. Concert films diversify artists'' revenue streams, allowing monetization beyond ticket sales. Additionally, the rising costs of attending live concerts—partly due to market monopolies like Ticketmaster—increase consumer interest in affordable alternatives. While films can provide a cost-effective and accessible option for fans, the initial financial investment and production costs often make this strategy prohibitive for independent artists.</p><p class="" style="white-space:pre-wrap;">Consumer preferences further drive the popularity of concert films. Modern audiences value convenience, affordability, and the intimacy films offer. Though concert films democratize event access for fans unable to attend live performances due to cost, geography, or limited ticket availability, these same high production values can exclude artists unable to afford these standards.</p><p class="" style="white-space:pre-wrap;">Overall, while the trend of turning music tours into cinematic experiences, exemplified by accessible yet challenging cases like Courtney Barnett''s "Anonymous Club," historical benchmarks such as Talking Heads'' "Stop Making Sense," and high-profile adaptations like Taylor Swift''s "The Eras Tour," marks a strategic evolution, it also underscores significant financial and logistical obstacles for smaller independent artists. This shift, while reshaping the landscape of live and recorded music, highlights the widening gap between artists with substantial resources and those attempting to break through independently.</p></div>',
  'Concert films are reshaping the music industry, offering artists new ways to reach audiences. While stars like Taylor Swift lead with big-budget productions, indie musicians such as Courtney Barnett use intimate, story-driven films to connect with fans. This trend brings both opportunity and challen',
  'Feats.',
  '2025-04-18 10:00:00',
  'Editorial, Trends, Political',
  '',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Gender Crisis at SXSW London 02.06.2025',
  'gender-crisis-at-sxsw-london-02-06-2025',
  '[caption id="" align="alignnone" width="1200"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/45c49294-b4a3-4dc7-90f4-b655372f64c9/%40TJEPhotos_+-+Gender+crisis+Tom+-+SXSW+London+-+02-06-2025+-+041.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">As SXSW London made its much-anticipated European debut, the festival’s sprawling program of tech, art, and music converged in Shoreditch, drawing a diverse crowd of innovators, creators, and music lovers. Among the 100+ acts lighting up the city, Gender Crisis delivered a set that captured the raw, urgent spirit of modern punk.</p><p class="" style="white-space:pre-wrap;">The festival’s eclectic line up from everything corporate to the grunge underground grassroots venues. Gender Crisis, with their reputation for high-energy, punk performances, fit perfectly into this dynamic, embodying rebellion.</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749232574168-IU3V4M1IFB8WSXFKLKG3/%40TJEPhotos_+-+Gender+crisis+Tom+-+SXSW+London+-+02-06-2025+-+001.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749232574185-BZF305GW69SHFOFPMO3S/%40TJEPhotos_+-+Gender+crisis+Tom+-+SXSW+London+-+02-06-2025+-+002.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749232575696-HE8X0RALIXRN4X2D2MCO/%40TJEPhotos_+-+Gender+crisis+Tom+-+SXSW+London+-+02-06-2025+-+003.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1749232575579-X4W1CXOYP6RZ5SRGV08V/%40TJEPhotos_+-+Gender+crisis+Tom+-+SXSW+London+-+02-06-2025+-+004.jpg?format=original" />
  

  
