INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'High Regard Live @ Underworld Camden 11.09.2025',
  'high-regard-live-underworld-camden-11-09-2025',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">High Regard brought their unrelenting hardcore energy to The Underworld in Camden as part of their latest run of shows. The night captured exactly what the band have become known for: raw intensity, a crowd that was fully involved from the first note, and a set that never once took its foot off the gas. With heavy breakdowns, driving riffs and a commanding presence from vocalist Jacob McLean, the room was alive with movement — from stage-divers to circle pits — giving the performance the kind of chaotic edge that defines hardcore at its best.</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1758299940188-NUPB9Y97ZCRTCTGDTK0B/%40jeffvad3r42+-+High+Regard+-+Camden+Underworld+-+11-09-2025+-+004.jpg?format=original" />
  

  
