INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Ones to Watch: HotWax at TGE ‘23',
  'hotwaxtge23',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">HotWax have been on tip of everyone’s tongue for a while now, they exceed expectations,  push boundaries and put on one of the best shows The Great Escape has instore. </p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/69b57a5f-f5f0-42a1-b2fd-ae9c026b3253/DSC00026.jpg?format=original" alt=" TOM ELLIS TJEphotos/Feats.live "/>  TOM ELLIS TJEphotos/Feats.live [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Every year The Great Escape is the best place to scout out your new favorite band, with emerging artists playing across the city all day, everyday! HotWax had the The Beach Stage full to the brim, a big Brighton sunshine meant that it was an energy filled sweat box. HotWax have gone from playing DIY gigs to Supporting the Strokes and filling a tent full of industry professionals at The Great Escape this weekend.&nbsp;</p></div>


  
       [caption id="" align="alignnone" width="3956"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/e226d4d6-e119-4e00-9b7f-593c70c4d238/DSC00047.jpg?format=original" alt=" TOM ELLIS TJEphotos/Feats.live "/>  TOM ELLIS TJEphotos/Feats.live [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><br><br></p><p class="" style="white-space:pre-wrap;">HotWax have been on our radar for a while, a band that exudes energy, confidence and kicks up a fire gig. The trio have been exceeding expectations and recently released their latest singles ‘A Thousand Times’ and ‘Treasure’, they have been dominating the local scene and have infiltrated the minds of anyone who appreciates good music in Brighton. Explosive and exciting is one way to describe this new band, they have a exciting run this festival season alongside two gigs at Brighton’s favourite festival; they have Mad Cool, All Points East, &amp; Burn it down festival on their bill.</p><p class="" style="white-space:pre-wrap;"><br></p><p class="" style="white-space:pre-wrap;">They are accomplishing things that take artists years to do, they have an electrifying stage presence and held everyone captive throughout the whole of their set. The head-banged &amp; twirled around the stage as if they were headlining their own gig. Their post punk sound fused with gritty guitar riffs blared through Brighton seafront. The success&nbsp; for this band is unknown and unlimited if they carry on the way that they are. It won''t be long till we’ll be watching them headline shows across the nation and trust me you’ll want to be there.</p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1e84d011-3f0d-4a6a-a646-3903f7a6ece4/DSC00069.jpg?format=original" alt=" TOM ELLIS TJEphotos/Feats.live "/>  TOM ELLIS TJEphotos/Feats.live [/caption] 
  

<iframe style="border-radius:12px" src="https://open.spotify.com/embed/artist/237mvWGlQNJJhc9b8pSawZ?utm_source=generator&theme=0" width="100%" height="380" frameBorder="0" allowfullscreen="" allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture" loading="lazy"></iframe>
<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><br><br><br></p></div>',
  'HotWax have been on tip of everyone’s tongue for a while now, they exceed expectations,  push boundaries and put on one of the best shows The Great Escape has instore. ',
  'Feats.',
  '2023-05-12 14:05:50',
  'THE GREAT ESCAPE',
  '/images/articles/DSC00026.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'The Importance of Balance Over Burnout',
  'importance-of-balance-over-burnout',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">“<em>If you love what you do, you’ll never work a day in your life</em>” is the same phrase that leads every creative into the depths of mental exhaustion. </p></div><hr />


  
      <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/5b464e8e-00b7-43be-be30-96dc546518c4/Edited+%2824+of+137%29.jpg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">I would like to say that I have always been aware of this, but six years into a career as a creative freelancer. Only now, have I finally managed a summer with a work life balance, that has promoted my well – being as the top priority. </p><p class="" style="white-space:pre-wrap;">It’s easy to say well balance is easy – “<em>define your working hours</em>”, “<em>eat well</em>”, “get your 8 hours” and “take regular breaks”. But when one doesn’t unpack the economic, social and personal factors that lead budding creatives into burnout. There is a lack of awareness, and therefore the problem persists.</p><p class="" style="white-space:pre-wrap;">I’ve watched plenty of podcasts where guests talk about the importance of “saying no.” Although there is truth to this, where the matter falls short is where it fails to acknowledge working class creatives who are scared to say ‘no’ in fear of not seeing another pay check. Or those who are working for lower/ or no fee to build their skills. For these reasons, the 8 hour sleep “routine” becomes impossible, eating well even harder when on the go and taking regular breaks becomes a myth.</p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><strong>So, what does help?</strong></p><p class="" style="white-space:pre-wrap;">For me it has been about making small changes where I can. The moment I realised that loving what I do, was leading me into exhaustion therefore, feelings of un motivation, procrastination and poor well – being. Was the moment that I realised I was living by an unhealthy schedule. </p><p class="" style="white-space:pre-wrap;">Acknowledging the signs is essential. These are not limited to, but include; struggles with basic work, procrastination, constant exhaustion, unhealthy comparisons, self-doubt and dread. </p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Although overcoming creative burnout can be challenging, it is not impossible. </p><p class="" style="white-space:pre-wrap;">If it feels comfortable speaking to a professional can be a highly effective way to begin to overcome the feeling. <a href="https://www.musicmindsmatter.org.uk/" target="_blank">Music Minds Matter</a> and <a href="https://www.musicsupport.org/" target="_blank">Music Support</a> are just two examples of incredible organisations providing support for those in or employed by the UK Music Industry. Other services like the Employee Assistance Programme or <a href="https://www.samaritans.org/how-we-can-help/contact-samaritan/talk-us-phone/" target="_blank">The Samaritans</a> also offer free confidential advice if you just need a friendly voice over the phone.</p><p class="" style="white-space:pre-wrap;">Set boundaries and prioritise tasks where possible. Being a freelancer it feels like anyone can contact you at any point in the day. And for me, I have always hated the fact I am always on my phone. If you can, setting a cut off time is extremely effective if the messages aren’t urgent a longer response time won’t hurt anyone! Prioritizing tasks is also essential. I’ve always been one to over pack my days and only allow myself rest when every one is ticked off. However, acknowledging this as unrealistic and living by a more flexible schedule has really graced me with peace of mind.</p></div>


  
      <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/a50a96d1-ea17-4d33-bf80-8ece23e2f7b9/Gig+On+The+Green+%28124+of+184%29.jpg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Whilst it was annoying to hear from others on loop. Genuinely understanding the “importance of the journey” was something I have begun to engrain. Therefore, being more accepting of the lows and living further in the highs of the process has been a real turning point and reset the pace completely. As they say, slow and steady always wins the race. </p><p class="" style="white-space:pre-wrap;">Collaboration is innovation. In an industry where it’s easy to feel alone, it’s always important to remember you never are. Only in the past few months have I really discovered the benefits of collaboration, being able to learn with others not only relieves pressure but allows the opportunity to fail and grow together. As creative people we are all just working it out, so it’s important not to forget that most will be happy to help where they can. </p><p class="" style="white-space:pre-wrap;">As much as you may love what you do, engaging in non-creative activities is as effective as switching off after a 9-5. Whilst I am fortunate enough to have friends in the creative circle, I have many who work outside of it which always gives me a nice bit of room to escape the constant chats about “what I have coming up next”. The gym is another core part of my routine, I am no JasmineFitUK but exercise provides me a complete mental reset. Sometimes my best ideas have come from me panting on a treadmill for 30 minutes. As someone who works most weekends, I have tried to make Mondays my self-care sanctuary and have spent some of the last few; Quad Biking, Boating, Biking and Bobsledding (I know quirky). So if it’s a day, or even a few hours if you can don’t underestimate the importance of a walk or quick catch up as a means of releasing serotonin. </p><p class="" style="white-space:pre-wrap;"><br></p><p class="" style="white-space:pre-wrap;">Burnout isn’t permanent, it’s a temporary. And whilst it may feel impossible and long winded it is possible to get to the point of balance over burnout. Creativity is powerful, but being kind to yourself is essential. </p></div>',
  '“If you love what you do, you’ll never work a day in your life” is the same phrase that leads every creative into the depths of mental exhaustion. ',
  'Feats.',
  '2025-07-25 12:00:00',
  'Editorial, Wellbeing',
  '/images/articles/Edited+%2824+of+137%29.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'James Marriott celebrates ‘Don’t Tell the Dog’ at his 100th show at Brighton Dome',
  'james-marriot-brighton-dome-19-november-2025',
  '[caption id="" align="alignnone" width="1000"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/211e4bde-67bf-47f7-83de-2d8384378648/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+132.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">James Marriott took to one of the south coasts’ most iconic venues for his 100th show, a sold out gig at Brighton’s Dome on the 19th November, a venue that has hosted icons past &amp; present. James Marriott not only did it justice, but absolutely blew me away. James took his hometown to celebrate ‘Don’t Tell the Dog’ his most recent record which became James’ first number 1 album&nbsp;</p><p class="" style="white-space:pre-wrap;">Here at Feats, we have been lucky enough to have been following James right from the beginning, His show at London’s The Garage to The Great Escape where Jubilee Street was overflowing. From the first moment that Ventriloquist came over the speakers &amp; the bright light strobes flashed away I realised this show was an entirely different calibre of what we have seen before.&nbsp;</p></div><hr />


  
       [caption id="" align="alignnone" width="1000"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/f7b2b726-c391-4408-9c1e-54db2f198e1b/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+094.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Before james was even on stage the crowd buzzed away, all singing along to the preshow playlist &amp; excitedly pointing at James’ Friends sat on the balcony. The lights dimmed, the band followed by james came on to the stage and the crowd was electric, singing every word from the first line throughout to the last moments until the house lights came on.&nbsp;</p><p class="" style="white-space:pre-wrap;">The Production for this run was incredibly designed, lampposts with illuminating power lines, parallel strobes that alternated flashing producing alternating shadows on to the backdrop. Sometimes stage production can fall flat, or feel barely stringed together, this was not like that. It felt well thought out, and looked breath taking.&nbsp;</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607247296-FLCYBRV5NRXGYI63SJ2I/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+029.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607247453-PSH0VMDOBX1SMDD6ZS93/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+034.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607248403-V4N9R4GRY2RUA3C3Z5AR/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+057.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607248757-WSGGI3P8X5OZE0GY593R/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+117.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607249578-ZOEB9B3QMXXDBEBAQ1B8/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+008.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607249750-E4J2ME48DOSX4UBQU7MZ/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+026.jpg?format=original" />
  

</div>
<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Between songs, James smoothly caught a Brighton &amp; Hove football shirt with 100 on the back, a tribute to this being his 100th show. “We have sung this song a lot together &amp; everytime we do you get a bit louder”</p><p class="" style="white-space:pre-wrap;">Car lights. This, admittedly is probably my favourite James Marriott song, it’s emotional, beautifully written and gut wrenchingly relatable.&nbsp;</p><p class="" style="white-space:pre-wrap;">Every lyric is screamed back at James in unison, one perfectly in time, accidental choir. Watching everyone scream the lyrics out at any show always chokes me up, seeing the devotion that live music fans have is special and the atmosphere is always something that can’t be replicated outside of it. James Marriott fans are some of the loudest I have ever heard.&nbsp;</p><p class="" style="white-space:pre-wrap;">As ‘Limbs’ played the emotions only grew, acoustically, on stage alone, James played out.&nbsp; Followed by Unreleased ‘California Rain’ - the reaction from the crowd was huge, with few singing along to the unreleased song probably learning the tune from other shows’ videos on YouTube.&nbsp;</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607362693-QJ7SB07841GP6UUGVDPD/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+062.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607362822-OHENTGEGIB3BG417W4IU/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+066.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607363917-FRWV7CFZR1YBS3XPOG3B/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+079.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607363999-B8RWPHH67E2AVHL2NDLJ/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+102.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607364996-Q8TLBENGLW08CJJLEMQH/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+107.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607365166-FF9NWO1KD56WLWGR5U95/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+125.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607366082-3IUGAV0E8J8EW1R186FL/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+130.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607366258-Z7LSINU49ZRQV8YKA5S0/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+133.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607367379-TXVD0AXWLTB3HIRHWW3P/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+020.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607367616-30WQRUREQ9N9G5VZC964/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+032.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1764607368507-OA1BP9EW3P6ENT915ZMG/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+033.jpg?format=original" />
  

</div>
<hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">James Marriott &amp; his band are exactly what Brighton Music scene embodies, energy, talent &amp; an excellent crowd, with Marriott’s Vocals &amp; the tenure of the band there was no better way to spend the evening!&nbsp;</p></div><script charset="utf-8" src="https://widget.bandsintown.com/main.min.js"></script><a class="bit-widget-initializer" data-artist-name="James Marriott" data-display-local-dates="false" data-display-past-dates="false" data-auto-style="false" data-text-color="#000000" data-link-color="#00b4b3" data-background-color="rgba(0,0,0,0)" data-display-limit="3" data-display-start-time="true" data-link-text-color="#FFFFFF" data-display-lineup="false" data-display-play-my-city="true" data-separator-color="rgba(255, 255, 255, 0.5)"></a>',
  'James Marriott took to one of the south coasts’ most iconic venues for his 100th show, a sold out gig at Brighton’s Dome on the 19th November, a venue that has hosted icons past &amp; present. James Marriott not only did it justice, but absolutely blew me away. James took his hometown to celebrate ‘',
  'Feats.',
  '2025-12-01 18:00:00',
  'Gig review, Live Music, Artist Showcase, Editorial',
  '/images/articles/%40TJEPhotos_+-+James+Marriott+Dome+-+Brighton+Dome+-+19-11-2025+-+132.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  '“Just Upload” - Max Fosh’s Advice for Young Creatives&nbsp;',
  'just-upload-max-foshs-advice-for-young-creatives-sxsw-london',
  '<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/808bddd0-39eb-4731-93af-fe15a3f74924/Max+Fosh+Press+Phoot.jpg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">In a world filled with so much noise, Especially with the AI slop that plagues our “for you” pages, standing out as a creative - whether that''s as a Musician, Filmmaker or Content Creator - Can be an incredibly daunting undertaking that can sometimes feel like you’re simply shouting into the void.&nbsp;</p><p class="" style="white-space:pre-wrap;">However, many do make it through this overcrowded space and are able to stand out and captivate the masses with their creativity. One such person is Youtube Sensation <a href="https://www.youtube.com/maxfosh"><span style="text-decoration:underline"><strong>Max Fosh</strong></span></a>, a UK-based YouTuber and comedian known for his hilariously absurd stunts and witty humour. He has built a standout brand, gaining over 4 Million subscribers &amp; more than 1.4 billion views across Youtube.. His approach to content creation holds valuable lessons for young creatives, who are looking to forge their own creative path.</p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><strong>Who are you? Introduction for our readers?</strong></p><p class="" style="white-space:pre-wrap;"><em>“Hello, my name is Max Fosh. I am a YouTuber and comedian based in the UK that primarily makes Silly content.”</em></p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><strong>You’ve got a very wide outreach &amp; good branding, all your content seem to follow the “Max Fosh” style, whilst remaining incredibly varied. I’m wondering if you could walk us through that, and how that impacts your decision making along the way when it comes to new projects?</strong></p><p class="sqsrte-small" style="white-space:pre-wrap;"><em>“So I''ve always, you know, been someone who''s been doing these very light-hearted, silly stunts and events, even when, you know, a camera hasn''t been following me. And so I try and keep that and keep that attitude when it comes to making the videos that I would be doing these things even if it wasn''t being filmed.&nbsp;</em></p><p class="sqsrte-small" style="white-space:pre-wrap;"><em>When it comes to video ideas themselves, title is the most important thing. YouTube is a very active form of watching, so people have to actively want to watch what you''ve got, rather than kind of algorithmic-based content like TikTok and Instagram where it''s kind of given to you, and so therefore your title needs to be incredibly interesting, it needs to be intriguing, and therefore we will come up with content ideas purely on what the title would be…</em></p><p class="sqsrte-small" style="white-space:pre-wrap;"><em>With (the) title, it''s just about juxtaposition, really, So for example, ‘I cooked a meal in a volcano’. Cooking a meal is something that we all know how to do in a volcano. There''s your juxtaposition, there''s your difference.</em></p><p class="sqsrte-small" style="white-space:pre-wrap;"><em>- So that''s kind of how a lot of the videos come about and how the ideas get formed.”&nbsp;</em></p><p class="" style="white-space:pre-wrap;"><br><br><br></p></div>


  
      <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/bc2f5807-d73e-4d39-a1ae-35fb31df54c9/press1.jpg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">For Max, he works backwards from the title, first developing a captivating title, using juxtaposition, creating a focal point around the content. From there he then builds out the rest of the video.&nbsp;&nbsp;</p><p class="" style="white-space:pre-wrap;">As a musician, you may want to focus on these “Gateways” for listeners to be pulled into your releases. Ask yourself, What’s your hook? How will a listener be drawn in to give your music a chance? What makes your next track or video stand out before someone hears a single note? Titles, visuals, and brand imagery are all fundamental for this.&nbsp;</p><p class="" style="white-space:pre-wrap;">Yes, great music/content comes first but before you release your next work to the world, next time, think. Think how you will draw in people to give up their next 3-5 minutes to your new release.</p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><strong>Whats the biggest challenge you’ve faced whilst being a content creator? And how did you overcome it?</strong></p><p class="sqsrte-small" style="white-space:pre-wrap;"><em>“The biggest challenge is understanding and learning how to build out a team and understand that you can''t do everything. When you start out as a content creator, you need to do everything. You need to produce, you need to edit, you need to film, you need to ideate, you need to be the accountant, you need to do everything.</em></p><p class="sqsrte-small" style="white-space:pre-wrap;"><em>And once you get to a certain level where you''re doing that regularly and over a number of years, you just start to burn out in a big, big way. And also, you''re not going to be good at all of those things. So understanding to relinquish the control and getting people in, if you can afford it and if the business works, who can take things off your plate to just remain creative.”</em></p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><p class="" style="white-space:pre-wrap;">Approaching this as a young musician, Yes, early on you’ll record, mix, promote, and manage yourself. But over time, building a trusted circle (whether it’s a co-writer, producer, manager, or even just supportive peers) can make your work more sustainable and keep your creativity alive. Without that supportive infrastructure you may fall into a burnout, so don''t be afraid to collaborate with others, bounce ideas with people, bring others into the fold that understand your vision and let your creativity flourish.</p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><strong>Whats your best advice for young creatives?</strong></p><p class="sqsrte-small" style="white-space:pre-wrap;"><em>“Just </em><strong><em>create”</em></strong><em>...“YouTube is an incredible platform in which anybody can be discovered. If you go to the Discovery page or the Recommended page on YouTube, there''ll be lots of videos that have very, very few amounts of views. YouTube wants to push new creators.</em></p><p class="sqsrte-small" style="white-space:pre-wrap;"><em>And so the best way in which you learn what you''re good at and what you''re not good at in your niche is by uploading. </em><strong><em>Always press upload</em></strong><em>. Just keep ideating and just try to improve a video by 1% every single time. And over the course of, you know, dozens, maybe even hundreds of videos, you''ll slowly get there. So it''s an incredible place, YouTube, for young creators, but you do, there''s no shortcut. There is no, you need to really, really put in the time and get good at your craft.”</em></p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><p class="" style="white-space:pre-wrap;">The exact same goes for music, and you may have heard it a thousand times but its doesnt make it any less true, create, create, create, on whatever platform. Stop waiting for perfection. Release your music. Learn from each drop. The difference between hobbyists and professionals isn’t always natural talent, it’s persistence.</p><p class="" style="white-space:pre-wrap;">Without creating consistently, you’ll never learn from your mistakes and you’ll always be at square one whenever approaching a track.&nbsp;</p><p class="" style="white-space:pre-wrap;"><strong>So just create.</strong></p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="sqsrte-small" style="white-space:pre-wrap;"><strong>If you could feature or collaborate with anyone, who would it be?<br>“</strong><em>If you could feature or collaborate with anyone, who would it be? Bo Burnham, very short and sweet. He''s kind of the inspiration to so many creatives and young people in the industry, whether it''s comedy or YouTube, and so he''s a real icon for me.”</em></p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><strong>Is there anything else you’d want to shout out or where can we find you</strong></p><p class="sqsrte-small" style="white-space:pre-wrap;"><em>“So there are some creators I''d love to shout out, some fantastic creators that I love in the&nbsp; (United) States, people like Andrew Video, Preston Goes, who are two kind of relatively established creators in the UK, who I think are absolutely amazing. In the UK, There''s a guy called Ali Gallop, who I think is fantastic. He makes more cinematic-style stuff, and I think he''s brilliant. So, yeah.”</em></p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><strong>Finally, Do you know what a grapefruit is now?</strong></p><p class="sqsrte-small" style="white-space:pre-wrap;">“<em>No. Famously, I don''t know my fruits.</em>”</p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><strong>What did we take away from the conversation-</strong></p><p class="" style="white-space:pre-wrap;">Throughout the entire conversation there were a few key themes that seemed to resonate:</p><ul data-rte-list="default"><li><p class="" style="white-space:pre-wrap;"><strong>Be true to your creative identity</strong> - don’t chase trends, chase truth.</p></li><li><p class="" style="white-space:pre-wrap;"><strong>Hook your audience early</strong> - visuals and branding matter just as much as sound.<strong><br>Build a team when you can - </strong>burnout helps no one.</p></li><li><p class="" style="white-space:pre-wrap;"><strong>Keep creating - </strong>Always upload. Iterate. Improve.<strong><br>Stay curious. </strong>Stay silly. And maybe... learn your fruits.</p></li></ul></div>',
  'In a world filled with so much noise, Especially with the AI slop that plagues our “for you” pages, standing out as a creative - whether that''s as a Musician, Filmmaker or Content Creator - Can be an incredibly daunting undertaking that can sometimes feel like you’re simply shouting into the void.',
  'Feats.',
  '2025-06-30 10:00:00',
  'Interview, SXSW London, Editorial, Social Media',
  '/images/articles/Max+Fosh+Press+Phoot.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Kids in Glass Houses Live @ Shepherd’s Bush 18.12.2025',
  'kids-in-glass-houses-shepards-bush-18-12-2025',
  '<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1483def5-30e1-47ad-99eb-27c027437c62/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2821+of+26%29.jpg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">When <a href="https://open.spotify.com/artist/0d630stEgFcD3GTKZPZFzY?si=fxs3uToAQU2VfMMHX7wYjg"><span style="text-decoration:underline"><strong>Kids in Glass Houses</strong></span></a> hit the stage in London in mid-December celebrating 15 years of <a href="https://open.spotify.com/album/5iDzAlSZKZm6QUGrh1JHri?si=mG3fArnXSVaqJ0wuIK7FtA" target="_blank"><em>Dirt</em></a>, it didn’t feel like a nostalgic echo, it felt like a record being lived anew. The <em>Dirt</em> anniversary tour brought a room full of fans together to revisit a defining chapter in the band’s story, and Shepherd’s Bush Empire provided a warm, energetic setting for it.</p><p class="" style="white-space:pre-wrap;">Support came from <a href="https://open.spotify.com/artist/3lGO6uBIzoFyU6OoGMER1B?si=ojjoFs_PQ62m6EX3Dcylug"><span style="text-decoration:underline"><strong>Dead Pony</strong></span></a>, and they delivered a sharp, high-energy opening set that quickly got the crowd locked in. Their songs were punchy and vigorous, and the band moved with a confidence that made for a clean and exciting warm-up to the main act.</p><p class="" style="white-space:pre-wrap;">Earlier in the evening, <a href="https://open.spotify.com/artist/3QSwq9CQMjqe01RtbKqz0F?si=njvLw-wGQJ2ieN_oD-QT6A"><span style="text-decoration:underline"><strong>Girl Band</strong></span></a> were unfortunately unable to perform due to illness. While the cancellation was a shame for those who had been looking forward to it, it didn’t noticeably dampen the buzz around the room once things got underway.</p></div><hr />

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452950432-QZFKG8TZVXBOMBQA6QI5/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%282+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452964416-IXW8VHIZPDKWT0CQEDWF/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%285+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452977349-BVC34CW6KCWF1IVX3OGT/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2810+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452956951-RDUDDHT2CUE8E8IA4O3Q/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%283+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452950293-2F3SZMX2IVF8C3HJEQ3U/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%281+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452959293-Z4V7URKS50VMUVD2ST3Q/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%284+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452965089-IEN54MM2DNBHJ2YHXYKT/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%287+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452978510-NCNQMF2M4R1KDKXU2G6Y/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2811+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452983235-ZXX6164XYBXTD6Z8X4K8/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2812+of+26%29.jpg?format=original" />
  

</div>
<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Shepherd’s Bush Empire itself felt fitting for a night like this. Its tiered layout kept the crowd feeling close and involved, and the sound throughout was full without ever feeling overwhelming, important for an album-focused show where clarity matters as much as atmosphere. It’s the kind of London room where you’re aware of every shout and singalong, and that made the night feel like a shared experience rather than a standard gig.</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452987775-84DXUO3CTNIKWES3RTTR/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2817+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452995440-BDIXOS1SKLV91IQLR9SM/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2825+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452990690-PFAJF1H0T213PJOF3UD2/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2822+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452992059-D12NEUZCKCH6RMLUXILU/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2824+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452980672-8MSE11AEG3KLB8DZMKXK/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2815+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452987351-CJTO6WUVZZ26LGTT2XN9/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2818+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452985022-OMOLYYIA88FSSWIBHUO7/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2816+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452988902-XYYERMA51ZBA0CDKAF79/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2819+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452989650-JLEFNMZXSZ2CM3LPC5NE/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2820+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452991203-YJSROY7IW1T4FRX4CBPC/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2823+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452976644-2TVAPQHXSPLG0R0OAZ9N/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2814+of+26%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1767452995145-ATVJH59N0QH07CJJQ763/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2826+of+26%29.jpg?format=original" />
  

</div>
<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">The band delivered <a href="https://open.spotify.com/album/5iDzAlSZKZm6QUGrh1JHri?si=mG3fArnXSVaqJ0wuIK7FtA" target="_blank"><em>Dirt</em> </a>with pride and energy, playing the record front to back as part of this anniversary run.<a href="https://www.livenation.co.uk/event/kids-in-glass-houses-dirt-15th-anniversary-tour-birmingham-tickets-edp1603361?utm_source=chatgpt.com"> </a>Songs that once felt restless and young now carried a living-with-them weight, and moments of intense guitar and vocal energy sat neatly alongside the louder sing-back choruses. For fans who grew up with the record, it was a chance to relive those songs in the place where a lot of those memories first took shape.</p><p class="" style="white-space:pre-wrap;">After the album run through, Kids in Glass Houses rounded out the night with a punchy encore drawn from across their wider catalogue, leaving the crowd with a sense of both completeness and excitement. There was no theatrics, just true live connection,&nbsp; guitars ringing, voices raised, and that sense of a crowd singing together as one.</p><p class="" style="white-space:pre-wrap;">Kids in Glass Houses delivered an outstanding night filled with nostalgia, good vibes and rock-solid songs that still stand tall 15 years on. With Shepherd’s Bush Empire marking the penultimate date of the <em>Dirt</em> anniversary run, the show felt both celebratory and reflective, capturing exactly why this record, and this band, continue to matter. If this tour proved anything, it’s that Kids in Glass Houses remain a compelling live force, and if you’re a fan, making it to the next tour should be an easy recommendation.</p></div>',
  'When Kids in Glass Houses hit the stage in London in mid-December celebrating 15 years of Dirt, it didn’t feel like a nostalgic echo, it felt like a record being lived anew. ',
  'Feats.',
  '2026-01-03 16:00:35',
  'Live Music, Gig Review',
  '/images/articles/Kids+in+Glass+Houses+-+Shepards+Bush+Empire+-+%40LouisHitchPhotos+%2821+of+26%29.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Kymara closes out 4 Week residency at Casablancas Brighton',
  'kymara-closes-out-4-week-residency-at-casablancas-brighton',
  '<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1758811549642-GKFYH7B13XCTMY9J0CEQ/%40phoebe.photography_+-+Kymara+Casablancas+1+-+Casablancas+-+12-09-2025+-+049.jpg?format=original" />
  

  
