  '/images/articles/%40phoebe.photography_+-+Kymara+Casablancas+1+-+Casablancas+-+12-09-2025+-+049.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Lastelle Live @ The Dome London 18.09.2025',
  'lastelle-live-the-dome-london-18-09-2025',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><a href="https://open.spotify.com/artist/2BB6OyMcGIRSwJQfsmpjKJ?si=1Vjur_9bRNCC6WScvSU6Cw" target="_blank">Lastelle </a>took to The Dome in London as part of their current UK run, bringing a set that balanced soaring emotion with heavier bursts of energy. Known for weaving difficult and deeply personal themes into their music, the band delivered a performance that was both atmospheric and intense. The show carried moments of quiet reflection before erupting into full force, with the London crowd fully engaged throughout. It was the kind of night that demonstrated why they’ve quickly become one of the most talked-about names in the UK’s post-hardcore and alternative scene.</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1758538214215-KI2H55SPIHYD5TUSD1XK/%40jeffvad3r42+-+Lastelle+-+The+Dome+-+18-09-2025+-+011.jpg?format=original" />
  

  
