   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1758538221588-FD09KL2JPBU1YX2Z8GDH/%40jeffvad3r42+-+Lastelle+-+The+Dome+-+18-09-2025+-+006.jpg?format=original" />
  

  
