INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Latitude 2025 - Ones to Watch',
  'latitude-2025-ones-to-watch',
  '[caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/3ac37c79-1571-40f0-9ec6-fa32e10c8a5b/DSC01803_1.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="sqsrte-large" style="white-space:pre-wrap;">Latitude 2025 is back this July, taking over Henham Park once again with a line-up that’s looking genuinely exciting. Whether you’re here for the iconic headliners or to discover something new, this year’s bill has a real mix to shout about.</p><p class="" style="white-space:pre-wrap;">Top of the poster you’ll find names like <strong>Sting</strong>,<strong> Snow Patrol</strong>, and <strong>Fatboy Slim</strong>—all bringing serious crowd-pleasers to the fields. Imagine singing along to ‘Chasing Cars’ as the sun goes down, or dancing with your mates while Fatboy Slim deliver hit after hit. It’s the kind of Latitude moment that stays with you.</p><p class="" style="white-space:pre-wrap;">But what keeps Latitude feeling fresh is how well it balances the big names with rising talent—and 2025’s line-up is packed with artists on the up. Manchester’s<strong> Freak Slug</strong> is one of them, bringing an off-kilter, alternative sound with her new release “I Blow Out Big Candles”. It’s experimental, heartfelt and unlike anything else on the line-up.</p><p class="" style="white-space:pre-wrap;"><strong>The Wytches </strong>are another one to keep an eye on—gritty, loud, and full of energy. Expect a chaotic live show that hits hard. Over on the more melodic side, <strong>Somebody’s Child</strong> are set to play tracks from their upcoming album “When Youth Fades Away”, landing just before the festival. If you''re into well-crafted indie with a bit of emotional depth, you’ll want to catch their set.</p><h2 style="text-align:center;white-space:pre-wrap;"><strong>Ones to Watch</strong></h2><p class="" style="white-space:pre-wrap;">Among the emerging artists on the bill, a few names really stand out:</p><ul data-rte-list="default"><li><p class="" style="white-space:pre-wrap;"><strong>TTSSFU </strong>– Bold, brash and full of punk energy. Unpolished in all the right ways.</p></li><li><p class="" style="white-space:pre-wrap;"><strong>Young Athena</strong> – A fresh blend of R&amp;B and rap, delivered with real confidence and style.</p></li><li><p class="" style="white-space:pre-wrap;"><strong>Mandrake Handshake</strong> – Psychedelic pop that’s colourful, layered, and seriously hypnotic.</p></li><li><p class="" style="white-space:pre-wrap;"><strong>Ellur </strong>– Retro-tinged indie-pop with big choruses and a lot of heart</p></li></ul><p class="" style="white-space:pre-wrap;">They might be playing earlier in the day, but they’re the sort of acts people end up talking about all weekend.</p><p class="" style="white-space:pre-wrap;">Whether you’re front and centre for the headliners or wandering the woods discovering your next favourite band, Latitude 2025 is shaping up to be one of the summer’s real highlights. Grab your ticket, bring your wellies, and get ready—this one’s going to be special.<br></p></div><iframe style="border-radius:12px" src="https://open.spotify.com/embed/playlist/1ijFRI4jwr8odS1gofWbJa?utm_source=generator" width="100%" height="352" frameBorder="0" allowfullscreen="" allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture" loading="lazy"></iframe>',
  'Latitude 2025 is back this July, taking over Henham Park once again with a line-up that’s looking genuinely exciting. Whether you’re here for the iconic headliners or to discover something new, this year’s bill has a real mix to shout about.',
  'Feats.',
  '2025-03-28 19:01:23',
  'Festival, ONES TO WATCH, Lattitude',
  '/images/articles/DSC01803_1.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'From playing deep within the woods to headlining the sunrise stage: Let’s Eat Grandma @ Latitude.',
  'letseatgrandmatalatitude',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><span class="sqsrte-text-color--lightAccent">Sophie Bingham</span></p></div><iframe class="embedly-embed" src="//cdn.embedly.com/widgets/media.html?src=https%3A%2F%2Fwww.youtube.com%2Fembed%2Fo4l7eKPvm5g%3Ffeature%3Doembed&display_name=YouTube&url=https%3A%2F%2Fwww.youtube.com%2Fwatch%3Fv%3Do4l7eKPvm5g&image=https%3A%2F%2Fi.ytimg.com%2Fvi%2Fo4l7eKPvm5g%2Fhqdefault.jpg&key=61d05c9d54e8455ea7a9677c366be814&type=text%2Fhtml&schema=youtube" width="854" height="480" scrolling="no" title="YouTube embed" frameborder="0" allow="autoplay; fullscreen" allowfullscreen="true"></iframe><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">“It’s the scariest crowd in the world” explained Rosa one out of two of the best friends that form Let''s Eat Grandma, Rosa Walton, Jenny Hollingbury and I caught up for quick chat before they headlined the sunrise stage at Latitude, after years of working their way up the bill, their headline show was only hours away at their hometown festival, knowing that many of the locals who have seen them year after year would be in the crowd, some from their childhood who have songs written about them, nerves and excitement were flowing.&nbsp;</p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/fc1cd162-d33f-4449-98e5-1931cb609179/DSC03625.jpg?format=original" alt=" Tom Ellis (TJEphotos, Feats.) "/>  Tom Ellis (TJEphotos, Feats.) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">They recently released their third album, Two Ribbons which takes you on a journey through their friendship, Jenny explained that they hold this album so close to their hearts, it means an ‘awful lot’ to each of them as it delves through a particularly difficult time for the both of them, making this headline show all the more emotional. It was incredibly special for them, “ it forces us to look at the history of the band, we''ve been doing this for so long and it''s easy to forget where we came from”&nbsp;</p><p class="" style="white-space:pre-wrap;">Let’s eat grandma has <em>always</em> been significant for the duo, they met when they were just four in nursery, and it seems they haven''t left each other''s side since. What makes them so easy to connect with is that it is so obvious how close they are, their warm and friendly energy exudes right through one another and into their music. Apart from their genius use of instruments and their emotional and powerful lyrics, this energy is what attracts people to their music.</p></div>


  
      <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/c585d046-b5ff-4289-bc4e-c3f374bf67ea/DSC03497.jpg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><em>‘Two Ribbons’</em> explores this, this album, for the first time ever, has a lead vocalist on each track, like an open letter to the other. Two Ribbons explores so many different things, to losing a loved one, the difficulties of growing up and the intricacies in their friendship. Rosa kicks off the album with Happy New Year, a song full of nostalgia but an underlying anxiety about their friendship changing as they grow older and their individuality grows, and it''s not until the bridge where Walton accepts that they can grow together and still be their own person.&nbsp;</p><p class="" style="white-space:pre-wrap;">The album is closed with the title track <em>‘Two Ribbons’</em> where Hollingbury sings of their individual ribbons fraying away, growing apart but still wrapped around one another,&nbsp;</p><p class="" style="white-space:pre-wrap;"><em>“These places, they stay, but we''re changing</em></p><p class="" style="white-space:pre-wrap;"><em>Like two ribbons, still woven, although we are fraying”.</em>&nbsp;</p><p class="" style="white-space:pre-wrap;">They quickly came to realize their relationship had not come to a plateau but they had started to grow as individuals. After losing her boyfriend Jenny went through a period of grief, Let’s Eat Grandma had to cancel their North American tour as they focussed on healing themselves. They can’t wait to head their way across the pond for 16 dates in North America this November! Alongside a UK tour just before throughout October!</p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/563c1591-2591-46f8-8f31-ebea5a229020/DSC03336.jpg?format=original" alt=" Tom Ellis (TJEphotos, Feats.) "/>  Tom Ellis (TJEphotos, Feats.) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">In the midst of all their festival performances, Let’s Eat Grandma closed the Sunrise stage at Latitude, alongside Snow Patrol on the Main stage, their emotional connection hit the crowd through their music as everyone was entranced during <em>Donnie Darko</em>, for eleven minutes straight everyone was completely captured. It was the best way to close of a weekend of polite chaos and fun!&nbsp;</p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/ee977f09-6362-40d6-9256-14fcdb103a3f/DSC03452.jpg?format=original" alt=" Tom Ellis (TJEphotos, Feats) "/>  Tom Ellis (TJEphotos, Feats) [/caption]',
  'Let’s Eat Grandma have recently realised their newest music video for ‘Watching You Go’, they''ve headlined Latitude, and are flying everywhere for their newest tour, we caught up with them to talk everything Let’s Eat Grandma!',
  'Feats.',
  '2022-09-08 13:30:00',
  'Interview, up and coming, Festival',
  '/images/articles/DSC03625.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'After a two year wait, and a long hiatus, Lewis Capaldi debuts his extraordinary Headliner performance at Latitude Festival ‘22.',
  'lewis-capaldi-latitude-2022',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><span class="sqsrte-text-color--lightAccent">WRITTEN BY SOPHIE BINGHAM</span></p></div>


  
       [caption id="" align="alignnone" width="3186"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/48388cd4-7f9e-4038-a159-5517b0450633/DSC09883.jpg?format=original" alt=" Tom Ellis (Feats./TJEphotos)© "/>  Tom Ellis (Feats./TJEphotos)© [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Lewis Capaldi had his Latitude Festival Debut as he took to headlining the Obelisk stage at Latitude on Friday. 9:30pm, 10 minutes before Lewis was due to perform, the arena filled up swiftly, with everyone else flooding their way towards the stage. At 9:40 a remixed version of <em>Everybody</em> by the Backstreet boys blared over the speakers.</p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/0c02616e-8be5-4c22-a70a-1fdce1a05644/DSC09647.jpg?format=original" alt=" Tom Ellis (Feats./TJEphotos)© "/>  Tom Ellis (Feats./TJEphotos)© [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><br></p><blockquote><p class="" style="white-space:pre-wrap;"> “Lewis is back tonight” -in the iconic tune. The anticipation built up.</p></blockquote><p class="" style="white-space:pre-wrap;">As he stepped out wearing a good-old black hoodie and beige trousers nothing could be more on brand for the Scottish national. Without missing a beat, Capaldi started with ‘Grace’, one his most popular songs. After his hiatus, it was no surprise that everyone in the crowd (including us) belted the lyrics back at him. There was not a quiet spot at Latitude while he was performing! Confetti exploded out of the canons, it was sure a sight to see!</p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/bc8e4362-10fd-4da3-a56d-b7da26c38f00/DSC09681.jpg?format=original" alt=" Tom Ellis (Feats./TJEphotos)© "/>  Tom Ellis (Feats./TJEphotos)© [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">He joked with the audience that he had ‘no new music’ because he was ‘too lazy’, he explained that he was <em>supposed t</em>o have finished the album but instead they were going to ‘play the old stuff’. Henham Park erupted in huge cheers, happy to just have lewis’ presence&nbsp; and excited to hear his old songs again.&nbsp;</p><p class="" style="white-space:pre-wrap;">He continued on with everyone screaming the emotional lyrics to Hold Me While You Wait, feeling every emotion. He followed up by playing the first song he ever released, bruises, independently releasing back in 2017, five years later and everyone still remembers it word for word.&nbsp;</p><p class="" style="white-space:pre-wrap;"><br></p><p class="" style="white-space:pre-wrap;"><em>‘I''ve been told, I''ve been told to get you off my mind</em></p><p class="" style="white-space:pre-wrap;"><em>But I hope I never lose the bruises that you left behind’</em></p></div>


  
       [caption id="" align="alignnone" width="4140"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/756d1ffd-dc89-484f-ad7d-43a91b0f5154/DSC09751_1.jpg?format=original" alt=" Tom Ellis (Feats./TJEphotos)© "/>  Tom Ellis (Feats./TJEphotos)© [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">He mentioned earlier in the set that he was worried that people had moved on.</p><blockquote><p class="" style="white-space:pre-wrap;"> ‘I always worry that people had forgotten us’. </p></blockquote><p class="" style="white-space:pre-wrap;">There is no way that anyone could ever forget his name,&nbsp; his songs or his incredibly genuine performance that he put on at Latitude Festival, he was sure a perfect Headliner for Friday night.</p><p class="" style="white-space:pre-wrap;">He however teased that new music would be out “soon”, he corrected himself after saying that new music would out next year, so it is safe to say that we will have new songs from this mega-star before the year is done. Going by his track record, I''m sure that his new releases will be met with tons of support and success. And that''s exactly what he deserves!</p><p class="" style="white-space:pre-wrap;">Sophie Bingham, Feats. ©</p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/472cc152-c4cb-43a4-ba33-d1280a293d2c/DSC00152.jpg?format=original" alt=" Tom Ellis (Feats./TJEphotos)© "/>  Tom Ellis (Feats./TJEphotos)© [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><br></p></div>',
  'Lewis Capaldi took to the Obelisk on Friday night for his debut performance at Latitude Festival- and we couldn’t have loved it more',
  'Feats.',
  '2022-07-23 16:04:00',
  'Live Music, Festival',
  '/images/articles/DSC09883.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Lovejoy: a band exploding out of the music scene!',
  'lovejoy-liveatleeds',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="sqsrte-small" style="white-space:pre-wrap;"><strong><em>*Update 2025</em></strong><em>* - LoveJoy have been at the center of a large amount of controversy since the release of this article in 2022, for this reason this Article has been Archived</em></p></div><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Lovejoy are exploding out of the music scene, 2022 was a HUGE year for them, within the music industry this mysterious band are turning heads, selling out tours in seconds and having a massive, loyal fanbase! Who are they? And where did they come from? </p><p class="" style="white-space:pre-wrap;">They are -the- band to watch out for in 2023.</p><p class="" style="white-space:pre-wrap;"><span class="sqsrte-text-color--lightAccent">Sophie Bingham</span></p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/f31d913b-cd65-4cf4-9565-589c52024990/LoveJoy+%2828+of+35%29.jpg?format=original" alt="  Louis Hitchcock (LouisHitchPhotos, Feats.)  "/>   Louis Hitchcock (LouisHitchPhotos, Feats.)  [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Heading back to October 2022 Feats had the pleasure to cover Live At Leeds: in the city, a venue hopping festival that is sure to discover tons of new talent, here is where we saw Lovejoy. </p><p class="" style="white-space:pre-wrap;">Fronted by Will Gold, and composed of Ash Kabosu, Joe Goldsmith and Mark Boardman&nbsp; this Brighton based band are coming off the leg of their first Northern UK tour, and exclusive London and Brighton dates, selling out each venue in sheer minutes, this is a band that you don''t want to miss! Playing their biggest hits ‘One Day’ and ‘Sex Sells’ joined with their trumpeters Leandra and Zoe onstage Lovejoy put on more than a show!</p><p class="" style="white-space:pre-wrap;">They''re playing sold out shows across the UK and Europe and recently announced two shows in the US: New York and LA, which, unsurprisingly also sold out in seconds! </p><p class="" style="white-space:pre-wrap;">Sky-rocketing out of lockdown, Lovejoy have only just began their career, with about 18 months under their belt, debuting their first EP back in March 2021. Lovejoy are so much more than ‘Wilbur Soot’s’ band, Will Gold’s internet Persona hitting millions across social media platforms, it feels like lovejoy have come out of nowhere taking over the music scene and surprising everyone with their ability to sell out their shows in literal seconds the question within the industry is who is this band? And where did they come from?</p></div>


  
       [caption id="" align="alignnone" width="6000"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/578f53b7-3c08-4ee8-b7c0-f43316dd55ba/DSC00117-2.jpg?format=original" alt="  Sophie Bingham (DisplacedImages, Feats.)  "/>   Sophie Bingham (DisplacedImages, Feats.)  [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Along with sold out shows and sold out merch, Lovejoy fans are very loyal, with fans queuing around the block before Midday. Thousands sat outside Leeds Beckett Student Union, with a capacity of only 1,100, thousands were still waiting outside hoping for a glimpse of the band or to hear the music outside. From the second the band walked out to their final thanks and goodbyes the energy was unmatched. Everyone was screaming each track word for word, excited to be seeing the band. Although Lovejoy’s Leeds appearance was part of Live At Leeds festival, it could have easily been a Lovejoy headline show!</p><p class="" style="white-space:pre-wrap;">Even unreleased tracks that were played at the show were met with screams and lyrics shouted back at them with fans learning them from previous videos of the show, Twitter was flooded with videos after the gigs!</p><p class="" style="white-space:pre-wrap;">Will has teased the new EP coming soon on a live twitch stream, with no other details being shared this band has a mysterious vibe about them, it’s definitely something intriguing that can’t help but pull people in.&nbsp;</p></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/990c292d-9cb5-4bd6-9578-17c423c496e5/LoveJoy+%2835+of+35%29.jpg?format=original" alt="  Louis Hitchcock (LouisHitchPhotos, Feats.)  "/>   Louis Hitchcock (LouisHitchPhotos, Feats.)  [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Lovejoy have perfectly crafted their onstage sound, the Trumpets add something special and new to a usual indie band sound, Their songs driven by Mark Boardmen’s double kick and his ‘metal style’ drumming adding to that unusual special sound that they have. Lovejoy are almost bordering a heavier style of music and this something, I personally hope they hone into on their new record.</p><p class="" style="white-space:pre-wrap;">They definitely pay homage to that old school brit pop sound like blur and fueled with their open and honest lyrics their songs are bound to be catchy.</p><p class="" style="white-space:pre-wrap;"><br>2023 definitely has some exciting things coming for Lovejoy, I can’t wait to see what direction they go in!<br><br><span class="sqsrte-text-color--lightAccent">Sophie Bingham</span></p></div>


  
       [caption id="" align="alignnone" width="3417"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/851e5ce7-9121-455b-81b2-cfc516a0f6c6/LoveJoy+%2824+of+35%29.jpg?format=original" alt="  Louis Hitchcock (LouisHitchPhotos, Feats.)  "/>   Louis Hitchcock (LouisHitchPhotos, Feats.)  [/caption]',
  'Lovejoy are exploding out of the music scene, Who are they? Where have they come from? They are the ones to watch out for in 2023.',
  'Feats.',
  '2023-01-04 12:00:00',
  'up and coming, Festival, concert',
  '/images/articles/LoveJoy+%2828+of+35%29.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'LUNCH Reveal UK Dates to Preview Upcoming EP and ''Cliffhanger’',
  'lunch-reveal-uk-dates-to-preview-upcoming-ep-and-cliffhanger',
  '<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/401c2b93-7a50-4696-ba40-c44ccad57c8c/TOUR%21+We%E2%80%99re+coming+to+you+this+Spring+if+where+you+are+is+on+this+list+of+placesHear+the+new+EP+and+a+very+special+live+set+crafted+around+it.+Tickets+for+all+shows+in+our+bio10-05+MANC+%40theratandpigeonmcr+w-+%40big_0ther+11.jpg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><em>“You catch yourself staring at this constant feed of bad news like it’s some TV show happening in another place, as if you’re so detached you become some kind of armchair critic of these terrible, real time events. It feels so unbelievable that it’s like someone wrote it, like it couldn’t be true. You want to be invested, to understand all these simultaneous plights and to do something about it but there’s so much happening that it’s overwhelming.”</em></p><p class="" style="white-space:pre-wrap;"><em>“But clearly it’s a privilege to sit here and feel ‘overwhelmed’ by shocking news when other people are the ones suffering the events themselves. So these lyrics are me poking fun at myself about that, playing the character of some subscription-paying keyboard warrior complaining about the plot of a TV show. It’s me trying to keep myself in check.”</em></p><p class="" style="white-space:pre-wrap;">Known for their explosive live shows, LUNCH blend elements of noise-rock and post-punk, described by Sarah Gosling of Radio X as “Dark Indie party hooks meet lyrical lunacy meet post-punk vocals and drums, and the whole thing''s just cracking carnage.”<br><br>The band describes their sound as “the raw aggression reminiscent of <a href="https://open.spotify.com/artist/0bPAi2zCrxUrPBREWdetZ5?si=ceiamQ7ZTIyEl1olJ46IGA"><span style="text-decoration:underline"><strong>GURRIERS </strong></span></a>and the angular guitar style of <a href="https://open.spotify.com/artist/3MM8mtgFzaEJsqbjZBSsHJ?si=sJ9_g4NRQPi88uKkAKh7Fw"><span style="text-decoration:underline"><strong>BLOC PARTY</strong></span></a>, topped with sharp commentary akin to<a href="https://open.spotify.com/artist/3xByNj8XW17oW0wsJhgzYL?si=kBzn0RfbSKSPrRE5jm_1BA"><span style="text-decoration:underline"> <strong>SOFT PLAY</strong></span></a>.”</p><p class="" style="white-space:pre-wrap;">The tour begins on 10 May at Manchester''s Rat &amp; Pigeon, supported by <a href="https://www.instagram.com/big_0ther/"><span style="text-decoration:underline"><strong>Big Other</strong></span></a>. On 11 May, LUNCH head to Nottingham''s The Grove alongside <a href="https://www.instagram.com/thistle.thistle.thistle/"><span style="text-decoration:underline"><strong>Thistle</strong></span></a>, followed by a show at Brighton''s Pipeline on 12 May with <a href="https://www.instagram.com/stereo.glue/"><span style="text-decoration:underline"><strong>Stereo Glue</strong></span></a>.</p><p class="" style="white-space:pre-wrap;">A standout event will be the free-entry show at Northampton''s Garibaldi Hotel on 16 May, featuring <a href="https://www.instagram.com/shtepimusic/"><span style="text-decoration:underline"><strong>Shtepi</strong></span></a>. The tour wraps up in London at Paper Dress Live on 6 June, joined by&nbsp; <a href="https://www.instagram.com/bones_ate_arfa/"><span style="text-decoration:underline"><strong>Bones Ate Arfa</strong></span></a>.</p><p class="" style="white-space:pre-wrap;">Tickets for all dates, except the free Northampton show, are available via the band''s Instagram page.</p><p class="" style="white-space:pre-wrap;">LUNCH Spring 2025 UK Tour Dates:</p><ul data-rte-list="default"><li><p class="" style="white-space:pre-wrap;">10 May – Manchester @ The Rat &amp; Pigeon (with <a href="https://www.instagram.com/big_0ther/"><span style="text-decoration:underline"><strong>Big Other</strong></span></a>)</p></li><li><p class="" style="white-space:pre-wrap;">11 May – Nottingham @ The Grove (with <a href="https://www.instagram.com/thistle.thistle.thistle/"><span style="text-decoration:underline"><strong>Thistle</strong></span></a>)</p></li><li><p class="" style="white-space:pre-wrap;">12 May – Brighton @ The Pipeline (with <a href="https://www.instagram.com/stereo.glue/"><span style="text-decoration:underline"><strong>Stereo Glue</strong></span></a>)</p></li><li><p class="" style="white-space:pre-wrap;">16 May – Northampton @ The Garibaldi Hotel (with <a href="https://www.instagram.com/shtepimusic/"><span style="text-decoration:underline"><strong>Shtepi</strong></span></a>) <em>Free Entry</em></p></li><li><p class="" style="white-space:pre-wrap;">6 June – London @ Paper Dress Live (with <a href="https://www.instagram.com/bones_ate_arfa/"><span style="text-decoration:underline"><strong>Bones Ate Arfa</strong></span></a>)</p></li></ul><p class="" style="white-space:pre-wrap;">For tickets and further information, visit LUNCH on Instagram at <a href="https://www.instagram.com/lunchbanduk/"><span style="text-decoration:underline">@lunchbanduk</span></a>.</p></div><iframe style="border-radius:12px" src="https://open.spotify.com/embed/artist/6WmAdVPZZxfEsu0eWIgWk8?utm_source=generator" width="100%" height="352" frameBorder="0" allowfullscreen="" allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture" loading="lazy"></iframe>',
  'East London indie band LUNCH have announced a UK tour this spring, featuring performances across several cities to promote their latest single, "Cliffhanger," and preview their upcoming debut EP, Open Wide, expected later this year.',
  'Feats.',
  '2025-04-14 10:00:00',
  'Tour, Release Radar, News',
  '/images/articles/TOUR%21+We%E2%80%99re+coming+to+you+this+Spring+if+where+you+are+is+on+this+list+of+placesHear+the+new+EP+and+a+very+special+live+set+crafted+around+it.+Tickets+for+all+shows+in+our+bio10-05+MANC+%40theratandpigeonmcr+w-+%40big_0ther+11.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'The name on the tip of everyone’s tongues: Lynks’ Secret set at Latitude Festival.',
  'lynks-at-latitude',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><span class="sqsrte-text-color--lightAccent">Sophie Bingham</span></p></div><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Lynks surprised everyone on Saturday night with their secret set at The Alcove with Queer House Party.</p></div>


  
       [caption id="" align="alignnone" width="3130"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/f8ce985e-160a-4de9-b6b6-315ccd14a582/lynks+lat.jpg?format=original" alt=" Tom Ellis (Feats./TJEPhotos) "/>  Tom Ellis (Feats./TJEPhotos) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Saturday night at Latitude Festival closed with a bang, Lynks performed a secret set with Queer House Party at midnight, a perfect way to end the night. This self-proclaimed ‘masked drag monster’ has been named the ‘one to watch'' by everyone who''s seen them perform, collaborating with the likes of Frank Carter and the Rattlesnakes on their hit single ‘go get a tattoo’ while supporting them on their ‘Sticky’ tour.&nbsp;</p><p class="" style="white-space:pre-wrap;">Their unique style of performance fused with their unapologetic self blends to create a masterpiece on stage. Their recent release MEN, composed of 3 electronic-dance tracks with a punk influence will instantly get you moving. ‘Perfect human specimen’ which appears on the EP, combines techno-space music with honest lyrics making you fall in love with them straight away, and when you see them live it''s almost impossible to get them out of your head.&nbsp;</p></div>


  
       [caption id="" align="alignnone" width="3733"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/da601aca-5d3a-4ab1-8359-c3dec137836c/DSC01600.jpg?format=original" alt=" Tom Ellis (Feats./TJEPhotos) "/>  Tom Ellis (Feats./TJEPhotos) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Onstage Lynks embodies an alter-ego, wearing their icon mask, expect to see them wearing something ultimately quirky. Their set is more than just a gig, with choreographed dance moves, strobed lights and catchy beats, you will be dancing in no time. ‘Str8 acting’ and ‘everyone''s hot and I''m not’ lit up The Alcove on Saturday. Lynks explained that their performance was ‘last minute’ but after seeing them live multiple times you would never be able to tell. Lynks is an integral piece within the queer music scene, in an interview with NME, the queer punkster explained how easy it is to feel alienated within straight spaces, expressed in ‘‘Everyones hot (and I’m not)” lynks explores the idea of how it feels to be the “other” in a room full of beautiful people. While ‘str8 acting’ takes the opposite view, why would anyone want to conform to a ‘straight culture'', confined by what society thinks they should act, look and be seen as?. questioned by Lynks themselves ‘why the fuck should I ever wanna be str8 acting?’</p><blockquote><p class="" style="white-space:pre-wrap;">This one goes out to</p><p class="" style="white-space:pre-wrap;">All the ''gayboy''s in their mum''s clothes</p><p class="" style="white-space:pre-wrap;">To the ''lezbo''s in the front row</p></blockquote></div>


  
       [caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/4be6cb20-590e-42ff-be95-4257bde380bd/DSC01563.jpg?format=original" alt=" Tom Ellis (Feats./TJEPhotos) "/>  Tom Ellis (Feats./TJEPhotos) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">This song represents how it feels to be an outcast and Lynks has created a safe space for anyone who feels exactly like that, the question on the tip of everyone''s tongue, when will they get a chance to see them live? We''re asking the same question. Hopefully lynks will return with a headline tour soon enough sprinkling their energy across the UK once again.</p><p class="" style="white-space:pre-wrap;"><br></p><p class="" style="white-space:pre-wrap;">Sophie Bingham (Feats.)<br></p></div>


  
      <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/51aa1bb8-918e-4044-ae70-606392e805b9/DSC01637.jpg?format=original" alt=""/>',
  'The name on the tip of everyones tongues : Lynks’ Secret set at Latitude Festival.Lynks surprised everyone on Saturday night with their secret set at The Alcove with Queer House Party.',
  'Feats.',
  '2022-07-27 07:00:00',
  'Live Music, Festival',
  '/images/articles/lynks+lat.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Melin Meylin Live @ Norwich Arts Centre 09.05.2025',
  'melin-meylin-live-norwich-arts-centre-09-05-2025',
  '<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594748927-7FM4VM1T537GGQSA7ZAA/%40shardsoflight_+-+Bitw+-+Norwich+Arts+Centre+-+09-05-2025+%2810%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594747878-ZKY128H351HMNU77C90Q/%40shardsoflight_+-+Bitw+-+Norwich+Arts+Centre+-+09-05-2025+%288%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594747707-MV0C2LSYYU45D76IBBGA/%40shardsoflight_+-+Bitw+-+Norwich+Arts+Centre+-+09-05-2025+%289%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594749069-10C2KYHRHPVI07R9NL3W/%40shardsoflight_+-+Bitw+-+Norwich+Arts+Centre+-+09-05-2025+%285%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594750295-O4QJ3BFEDUIE2P5HBDST/%40shardsoflight_+-+Bitw+-+Norwich+Arts+Centre+-+09-05-2025+%286%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594750354-JWD59Y18LRCGWZSL1E3F/%40shardsoflight_+-+Bitw+-+Norwich+Arts+Centre+-+09-05-2025+%287%29.jpg?format=original" />
  

</div>
<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">The night started off at 8pm with a set from the wonderful and charming welsh singer Bitw who captivated the audience all by himself, and quickly had people coming in to listen. </p><p class="" style="white-space:pre-wrap;"><br>Whilst the stage was being setup for Melin Melyn many people flocked to the bar to get more refreshments ready for the main act, however those who stayed got to see the set unfold, including a life sized stuffed doll wearing a pink boiler suit and glasses to match the band. </p><p class="" style="white-space:pre-wrap;">Once Melin Melyn arrived they captured the audiences attention from the start, coming on stage and saluting everyone before starting the gig off. Their captivating energy allowing them to get strong audience engagement, including getting everyone to bark like a dog mid way through a song! With the set only pausing in between songs in order to talk about the importance of funding grassroots venues and supporting&nbsp;the&nbsp;arts.</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594794765-RKTITT9WDFJ31HXAQOF8/%40shardsoflight_+-+Melin+Meylin+-+Norwich+Arts+Centre+-+09-05-2025+%282%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594794941-714YHRS2M7G5P4DA4X6S/%40shardsoflight_+-+Melin+Meylin+-+Norwich+Arts+Centre+-+09-05-2025+%281%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594796419-IIRECUI3E526PNPWAV3D/%40shardsoflight_+-+Melin+Meylin+-+Norwich+Arts+Centre+-+09-05-2025+%283%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594796749-HRSTWRT2ZR2T78FSMFOG/%40shardsoflight_+-+Melin+Meylin+-+Norwich+Arts+Centre+-+09-05-2025+%284%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594797741-5HKZOTZ737W5ZHSDD9ER/%40shardsoflight_+-+Melin+Meylin+-+Norwich+Arts+Centre+-+09-05-2025+%285%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594797852-DC4XQNYUL78MVU906ARU/%40shardsoflight_+-+Melin+Meylin+-+Norwich+Arts+Centre+-+09-05-2025+%286%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594799079-CRHFC142YWMLRWL7PYGA/%40shardsoflight_+-+Melin+Meylin+-+Norwich+Arts+Centre+-+09-05-2025+%287%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594798941-H3592I3E7B10NNA9KGYR/%40shardsoflight_+-+Melin+Meylin+-+Norwich+Arts+Centre+-+09-05-2025+%288%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1747594800132-4C76S3FPS01HGZGUGJWJ/%40shardsoflight_+-+Melin+Meylin+-+Norwich+Arts+Centre+-+09-05-2025+%289%29.jpg?format=original" />
  

</div>',
  'Melin Melyn arrived they captured the audiences attention from the start, coming on stage and saluting everyone before starting the gig off. ',
  'Feats.',
  '2025-05-21 10:00:00',
  'Gig Review, Live Music, Artist Showcase',
