INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Ozzy Osbourne Dies at 76, Days After Final Birmingham Performance',
  'ozzy-osbourne-dies-at-76-days-after-final-birmingham-performance',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Ozzy Osbourne, the pioneering figure behind Black Sabbath and one of the most influential voices in heavy music, has died at the age of 76. His passing comes less than a week after what would become his final public performance - a homecoming show in Birmingham that reunited the original Black Sabbath lineup on stage for the first time in decades.</p></div>


  
       [caption id="" align="alignnone" width="1200"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/4bf2a3b3-845d-44b6-a166-b9b7f36b21b6/ozzy-osbourne-back-to-the-beginning-1.jpg?format=original" alt=" Photo Credit: Ross Halfin "/>  Photo Credit: Ross Halfin [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">The event, titled <a href="https://www.avfc.co.uk/concerts/back-to-the-beginning/"><span style="text-decoration:underline"><em>Back to the Beginning</em>,</span></a> took place at <a href="https://www.avfc.co.uk/"><span style="text-decoration:underline">Villa Park </span></a>and drew tens of thousands of fans to witness a celebration of Ozzy’s towering legacy. Performing seated due to ongoing health challenges, he was joined by Tony Iommi, Geezer Butler and Bill Ward in a send-off that felt as much like a tribute as it did a concert. The bill featured a huge cast of artists spanning generations of heavy music, including <a href="https://open.spotify.com/artist/2ye2Wgw4gimLv2eAKyk1NB?si=Nz_3WxPBTX6dqBbQCODENA"><span style="text-decoration:underline">Metallica</span></a>, <a href="https://open.spotify.com/artist/2yEwvVSSSUkcLeSTNyHKh8?si=L2jOkG_ZTwudlfNT1sF04w"><span style="text-decoration:underline">Tool</span></a>, <a href="https://open.spotify.com/artist/14pVkFUHDL207LzLHtSA18?si=V9RSkkZbSt2cEbE1T-iYWg"><span style="text-decoration:underline">Pantera</span></a>, <a href="https://open.spotify.com/artist/3qm84nBOXUEQ2vnTfUTTFC?si=csBDEsdLT5W4IbDIAwp8GQ"><span style="text-decoration:underline">Guns N'' Roses</span></a>, and a surprise appearance from <a href="https://open.spotify.com/artist/6Ad91Jof8Niiw0lGLLi3NW?si=xoiH9-OURcWgP4GbQqOOig"><span style="text-decoration:underline">Yungblud </span></a>- whose fiery performance brought a modern edge to the evening’s sense of occasion.</p></div><blockquote class="instagram-media" data-instgrm-permalink="https://www.instagram.com/p/DMa7gaKSb11/" data-instgrm-version="12" style=" background:#FFF; border:0; border-radius:3px; box-shadow:0 0 1px 0 rgba(0,0,0,0.5),0 1px 10px 0 rgba(0,0,0,0.15); margin: 1px; max-width:540px; min-width:326px; padding:0; width:99.375%; width:undefinedpx;height:undefinedpx;max-height:100%; width:undefinedpx;"><div style="padding:16px;"> <a id="main_link" href="p/DMa7gaKSb11/" style=" background:#FFFFFF; line-height:0; padding:0 0; text-align:center; text-decoration:none; width:100%;" target="_blank"> <div style=" display: flex; flex-direction: row; align-items: center;"> <div style="background-color: #F4F4F4; border-radius: 50%; flex-grow: 0; height: 40px; margin-right: 14px; width: 40px;"></div> <div style="display: flex; flex-direction: column; flex-grow: 1; justify-content: center;"> <div style=" background-color: #F4F4F4; border-radius: 4px; flex-grow: 0; height: 14px; margin-bottom: 6px; width: 100px;"></div> <div style=" background-color: #F4F4F4; border-radius: 4px; flex-grow: 0; height: 14px; width: 60px;"></div></div></div><div style="padding: 19% 0;"></div> <div style="display:block; height:50px; margin:0 auto 12px; width:50px;"><svg width="50px" height="50px" viewBox="0 0 60 60" version="1.1" xmlns="https://www.w3.org/2000/svg" xmlns:xlink="https://www.w3.org/1999/xlink"><g stroke="none" stroke-width="1" fill="none" fill-rule="evenodd"><g transform="translate(-511.000000, -20.000000)" fill="#000000"><g><path d="M556.869,30.41 C554.814,30.41 553.148,32.076 553.148,34.131 C553.148,36.186 554.814,37.852 556.869,37.852 C558.924,37.852 560.59,36.186 560.59,34.131 C560.59,32.076 558.924,30.41 556.869,30.41 M541,60.657 C535.114,60.657 530.342,55.887 530.342,50 C530.342,44.114 535.114,39.342 541,39.342 C546.887,39.342 551.658,44.114 551.658,50 C551.658,55.887 546.887,60.657 541,60.657 M541,33.886 C532.1,33.886 524.886,41.1 524.886,50 C524.886,58.899 532.1,66.113 541,66.113 C549.9,66.113 557.115,58.899 557.115,50 C557.115,41.1 549.9,33.886 541,33.886 M565.378,62.101 C565.244,65.022 564.756,66.606 564.346,67.663 C563.803,69.06 563.154,70.057 562.106,71.106 C561.058,72.155 560.06,72.803 558.662,73.347 C557.607,73.757 556.021,74.244 553.102,74.378 C549.944,74.521 548.997,74.552 541,74.552 C533.003,74.552 532.056,74.521 528.898,74.378 C525.979,74.244 524.393,73.757 523.338,73.347 C521.94,72.803 520.942,72.155 519.894,71.106 C518.846,70.057 518.197,69.06 517.654,67.663 C517.244,66.606 516.755,65.022 516.623,62.101 C516.479,58.943 516.448,57.996 516.448,50 C516.448,42.003 516.479,41.056 516.623,37.899 C516.755,34.978 517.244,33.391 517.654,32.338 C518.197,30.938 518.846,29.942 519.894,28.894 C520.942,27.846 521.94,27.196 523.338,26.654 C524.393,26.244 525.979,25.756 528.898,25.623 C532.057,25.479 533.004,25.448 541,25.448 C548.997,25.448 549.943,25.479 553.102,25.623 C556.021,25.756 557.607,26.244 558.662,26.654 C560.06,27.196 561.058,27.846 562.106,28.894 C563.154,29.942 563.803,30.938 564.346,32.338 C564.756,33.391 565.244,34.978 565.378,37.899 C565.522,41.056 565.552,42.003 565.552,50 C565.552,57.996 565.522,58.943 565.378,62.101 M570.82,37.631 C570.674,34.438 570.167,32.258 569.425,30.349 C568.659,28.377 567.633,26.702 565.965,25.035 C564.297,23.368 562.623,22.342 560.652,21.575 C558.743,20.834 556.562,20.326 553.369,20.18 C550.169,20.033 549.148,20 541,20 C532.853,20 531.831,20.033 528.631,20.18 C525.438,20.326 523.257,20.834 521.349,21.575 C519.376,22.342 517.703,23.368 516.035,25.035 C514.368,26.702 513.342,28.377 512.574,30.349 C511.834,32.258 511.326,34.438 511.181,37.631 C511.035,40.831 511,41.851 511,50 C511,58.147 511.035,59.17 511.181,62.369 C511.326,65.562 511.834,67.743 512.574,69.651 C513.342,71.625 514.368,73.296 516.035,74.965 C517.703,76.634 519.376,77.658 521.349,78.425 C523.257,79.167 525.438,79.673 528.631,79.82 C531.831,79.965 532.853,80.001 541,80.001 C549.148,80.001 550.169,79.965 553.369,79.82 C556.562,79.673 558.743,79.167 560.652,78.425 C562.623,77.658 564.297,76.634 565.965,74.965 C567.633,73.296 568.659,71.625 569.425,69.651 C570.167,67.743 570.674,65.562 570.82,62.369 C570.966,59.17 571,58.147 571,50 C571,41.851 570.966,40.831 570.82,37.631"></path></g></g></g></svg></div><div style="padding-top: 8px;"> <div style=" color:#3897f0; font-family:Arial,sans-serif; font-size:14px; font-style:normal; font-weight:550; line-height:18px;"> View this post on Instagram</div></div><div style="padding: 12.5% 0;"></div> <div style="display: flex; flex-direction: row; margin-bottom: 14px; align-items: center;"><div> <div style="background-color: #F4F4F4; border-radius: 50%; height: 12.5px; width: 12.5px; transform: translateX(0px) translateY(7px);"></div> <div style="background-color: #F4F4F4; height: 12.5px; transform: rotate(-45deg) translateX(3px) translateY(1px); width: 12.5px; flex-grow: 0; margin-right: 14px; margin-left: 2px;"></div> <div style="background-color: #F4F4F4; border-radius: 50%; height: 12.5px; width: 12.5px; transform: translateX(9px) translateY(-18px);"></div></div><div style="margin-left: 8px;"> <div style=" background-color: #F4F4F4; border-radius: 50%; flex-grow: 0; height: 20px; width: 20px;"></div> <div style=" width: 0; height: 0; border-top: 2px solid transparent; border-left: 6px solid #f4f4f4; border-bottom: 2px solid transparent; transform: translateX(16px) translateY(-4px) rotate(30deg)"></div></div><div style="margin-left: auto;"> <div style=" width: 0px; border-top: 8px solid #F4F4F4; border-right: 8px solid transparent; transform: translateY(16px);"></div> <div style=" background-color: #F4F4F4; flex-grow: 0; height: 12px; width: 16px; transform: translateY(-4px);"></div> <div style=" width: 0; height: 0; border-top: 8px solid #F4F4F4; border-left: 8px solid transparent; transform: translateY(-4px) translateX(8px);"></div></div></div> <div style="display: flex; flex-direction: column; flex-grow: 1; justify-content: center; margin-bottom: 24px;"> <div style=" background-color: #F4F4F4; border-radius: 4px; flex-grow: 0; height: 14px; margin-bottom: 6px; width: 224px;"></div> <div style=" background-color: #F4F4F4; border-radius: 4px; flex-grow: 0; height: 14px; width: 144px;"></div></div></a><p style=" color:#c9c8cd; font-family:Arial,sans-serif; font-size:14px; line-height:17px; margin-bottom:0; margin-top:8px; overflow:hidden; padding:8px 0 7px; text-align:center; text-overflow:ellipsis; white-space:nowrap;"><a href="https://www.instagram.com/p/DMa7gaKSb11//" style=" color:#c9c8cd; font-family:Arial,sans-serif; font-size:14px; font-style:normal; font-weight:normal; line-height:17px; text-decoration:none;" target="_blank">Shared post</a> on <time style=" font-family:Arial,sans-serif; font-size:14px; line-height:17px;">Time</time></p></div></blockquote><script async src="https://www.instagram.com/embed.js"></script><div style="overflow: auto; position: absolute; height: 0pt; width: 0pt;"><a href="https://wwwxxxcom.net/video/xx-video-direct">xx video direct</a></div><script type="text/javascript" src="https://instaembedcode.com/in.js"></script></div><style>.boxes3{height:175px;width:153px;} #n img{max-height:none!important;max-width:none!important;background:none!important} #inst i{max-height:none!important;max-width:none!important;background:none!important}</style></div><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">In the days since, tributes have poured in from across the music world. Artists from every corner of the industry have acknowledged the impact Ozzy had on shaping rock culture - not just through his records, but through the way he lived it. From chart-topping solo releases to reality television, festival curation and late-career collaborations, his presence extended well beyond metal.</p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Rising to fame in the 1970s as the voice of <a href="https://open.spotify.com/artist/5M52tdBnJaKSvOpJGz8mfZ?si=70AvNO3YSi2LfVqkGowL5Q"><span style="text-decoration:underline">Black Sabbath</span></a>, Ozzy helped lay the groundwork for what heavy music would become. Albums like <a href="https://open.spotify.com/album/4kA2o0L3tz9vFKJetiFUJI?si=RDajUE0-QLijNkKkA76jaA"><span style="text-decoration:underline"><em>Paranoid</em> </span></a>and <a href="https://open.spotify.com/album/24fNwoIq4NLDf4ARJYAFN9?si=dkHL9WjlTbqdRbQ7_KIwcQ"><span style="text-decoration:underline"><em>Master of Reality</em></span></a> introduced a darker, heavier sound that shifted the landscape of rock music altogether. His solo career, beginning with <a href="https://open.spotify.com/album/4qUMByJ3Pk94BFnCmGaUPS?si=7NRfpSSaR1Ce5x6jtLfO0A"><span style="text-decoration:underline"><em>Blizzard of Ozz</em></span></a> in 1980, brought a string of enduring tracks that would later define a generation of metal fans.</p><p class="" style="white-space:pre-wrap;">Throughout it all, he remained rooted in his origins - both musically and personally. That his final public appearance took place just a few miles from where it all began feels almost poetic. Even as his health declined, his commitment to performing never wavered.</p><p class="" style="white-space:pre-wrap;">Ozzy Osbourne’s contribution to music cannot be measured in albums sold or tours completed. His legacy lives in the sound and spirit of every band he inspired, every stage he lit up, and every artist who followed in his path. His passing marks the end of a monumental chapter, but the noise he made will echo for generations.</p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Farewell, Ozzy - and thank you for everything.</p></div>',
  'Ozzy Osbourne, the pioneering figure behind Black Sabbath and one of the most influential voices in heavy music, has died at the age of 76. His passing comes less than a week after what would become his final public performance — a homecoming show in Birmingham that reunited the original Black Sabba',
  'Feats.',
  '2025-07-23 13:00:00',
  'Editorial, News, Memorial',
  '/images/articles/ozzy-osbourne-back-to-the-beginning-1.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Pet Needs @ The Garage - 04.05.25',
  'pet-needs-the-garage-04-05-25',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">It’s the night of <a href="https://open.spotify.com/artist/5bBMfsANUM0cj5h5MjEdxP?si=6QsuIrWZRdy5WgE8fgzWoA" target="_blank">Pet Needs</a> biggest headline show to date and the wrap of their ‘Fractured Party’ , a weekend of live shows by the band. With fans travelling from all over the stage it set for a memorable night</p><p class="" style="white-space:pre-wrap;">Up first <a href="https://open.spotify.com/artist/7DEM6YRBFI1BYcyWYiZaJ5?si=LzlBkEuhSBKKvy_jxS6z2Q" target="_blank">Pageant Mum</a>, playing not long after doors opened people were still making their way in. With a slightly shorter 5 songs set they made a good effort to interact with the crowd and get them engaged. The set ended on an energetic high note.</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1746695991172-6DEF7CEN3UIF7SDFVB5E/%40c.shoots.shows+-+Pagent+Mum+-+The+Garage-+04-05-2025+%281%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1746695991294-UJOYEIDJIJR4UA8UYP46/%40c.shoots.shows+-+Pagent+Mum+-+The+Garage-+04-05-2025+%282%29.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1746695992365-AVE2HRQJZ56E3V1GDYLW/%40c.shoots.shows+-+Pagent+Mum+-+The+Garage-+04-05-2025+%283%29.jpg?format=original" />
  

  
