  'Live Music, Gig Review',
  '/images/articles/%40fox_trotter42+-+Thorby+-+The_Windmill+-+31-07-2025+-+005.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Ones To Watch: Sunday Best @ SXSW London',
  'sunday-best-at-sxsw-london-02-06-2025',
  '[caption id="" align="alignnone" width="1200"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/2cd9a229-7658-494f-b2bb-710f7a6af2da/%40TJEPhotos_+-+TE+Sunday+Best+-+Brick+Lane+Tap+Room+-+02-06-2025+-+040.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">South by SouthWest is in full swing, Shoreditch is bustling, the sun is out and Day 1 of it’s debut year has been incredibly successful and full of amazing bands and interesting talks. Sometimes finding heavy music at festivals can be a challenge but with a stellar lineup of bands at Brick Lane TapRoom (curated by London’s own BiteBack) we were in for a treat. Sunday Best, Mandragora &amp; Gender Crisis all took to the Taprooms Stage and it was electric.</p><p class="" style="white-space:pre-wrap;"><br></p><p class="" style="white-space:pre-wrap;">Sunday Best have been breaking into the heavy scene recently, with their latest single Dig Deep dropping, fusing groove-y guitars and ballard-esque vocals all building to an angry but powerful breakdown. Everyone should keep an eye out for Sunday Best, They embody what the scene is all about, inclusivity, representation and impeccable stage presence.&nbsp;</p></div>

<div class="image-gallery-wrapper">

  
