INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Sweet Pill Live @ Downstairs At The Dome 28.05.2025',
  'sweet-pill-live-downstairs-at-the-dome-28-05-2025',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">After a European run and their first ever appearance at Slam Dunk, Sweet Pill are rounding off this run of shows in London. Headlining Downstairs At The Dome to an almost sold out room</p></div>

<div class="image-gallery-wrapper">

  
