   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748953711854-E0SCW7N12VU3UD561JDN/%40c.shoots.shows+-+Pollyanna+-+Downstairs+At+The+Dome+-+28-05-2025+-+006.jpg?format=original" />
  

  
