INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Truck Festival 2025: Indie Spirit with a Big Heart',
  'truck-festival-2025-indie-spirit-with-a-big-heart',
  '<div class="sqs-html-content" data-sqsp-text-block-content><h3 style="text-align:center;white-space:pre-wrap;"><strong>Main Acts Lighting Up 2025</strong></h3><p class="" style="white-space:pre-wrap;">Truck’s reputation for showcasing new talent hasn’t stopped it from pulling in major headliners. This year the top of the bill is downright formidable. We’ve got <strong>Nothing But Thieves</strong> (playing an exclusive UK festival set), the ever-anthemic <strong>Kasabian</strong>, Manchester indie heroes <strong>Courteeners </strong>and alt-rock icons Bloc Party bringing the sing-along hits. Seeing such big names on a cosy farm stage is proof of how far Truck has come – the festival’s stature has snowballed without losing its soul.</p><p class="" style="white-space:pre-wrap;">The undercard is just as exciting. 2000s legends like <strong>Franz Ferdinand </strong>and The <strong>Futureheads</strong>, indie darlings <strong>Blossoms</strong>, cheeky chart-toppers<strong> Scouting for Girls</strong>, and pop-rock favourite <strong>Natasha Bedingfield</strong> (<em>as a special guest</em>) are all on the lineup. And true to Truck form, the bill is bursting with buzzworthy new bands: from hype-heavy <strong>The Last Dinner Party</strong> and Irish rockers T<strong>he Reytons</strong>, to quirky indie crew <strong>Sports Team</strong> and soulful songwriter <strong>CMAT</strong>, you’ll find stellar music on every stage before the headliners even play. Throw in a stacked comedy tent headlined by the inimitable <strong>Reggie Watts</strong>, and Truck 2025 promises non-stop entertainment at every turn.</p><h3 style="text-align:center;white-space:pre-wrap;"><strong>Ones to Watch</strong></h3><p class="" style="white-space:pre-wrap;">One of the best parts of Truck Festival is discovering tomorrow’s stars. Here are a few up-and-coming artists on the 2025 bill that you won’t want to miss – each bringing fresh music to the farm:</p><ul data-rte-list="default"><li><p class="" style="white-space:pre-wrap;"><strong>Courting </strong>– A post-punk outfit from Liverpool known for witty lyrics and genre-bending tunes. They’re fresh off releasing their adventurous third album “Lust for Life, or How To Thread The Needle…”, which landed in March to critical acclaim. Expect an unpredictable, high-energy set that shows why they’re rapidly becoming indie favourites. We caught up with them at 2000Trees a few years ago - You can watch the interview <a href="https://www.youtube.com/watch?v=eV3l0kQn-Bc" target="_blank">here</a>!</p></li></ul></div><iframe width="100%" height="315" src="https://www.youtube.com/embed/eV3l0kQn-Bc?si=JQ5KOZop7l717SeG" title="YouTube video player" frameborder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" referrerpolicy="strict-origin-when-cross-origin" allowfullscreen></iframe><div class="sqs-html-content" data-sqsp-text-block-content><ul data-rte-list="default"><li><p class="" style="white-space:pre-wrap;"><strong>Honeyglaze </strong>– This London trio delivers dreamy alt-rock with a twist. Their second album “Real Deal” dropped in late 2024, flipping the script on what alternative music can be. Honeyglaze’s incredible melodies and artful songwriting have won over critics and fans alike – catch their live show as they ascend the ranks of the indie scene.</p></li></ul><ul data-rte-list="default"><li><p class="" style="white-space:pre-wrap;"><strong>Picture Parlour </strong>– A fierce, all-female indie-rock outfit with big choruses and an even bigger presence. Their debut EP landed earlier this year and has been building buzz on the live circuit ever since. Gritty, stylish and full of intent – they’re ones to watch if you like your indie with teeth.</p></li><li><p class="" style="white-space:pre-wrap;"><strong>Kingfishr </strong>– Hailing from Ireland, Kingfishr blend folk storytelling with arena-sized indie rock hooks. These lads have been making waves with sing-along anthems (“<em>Man On The Moon</em>” is a fan favourite) and sold-out shows across Ireland and the UK. They haven’t even released a full album yet, but their heartfelt, big-sounding tunes already have festival crowds swooning – definitely one to watch as they rise.</p></li></ul><p class="" style="white-space:pre-wrap;"><strong>Truck Festival 2025</strong> is shaping up to be a special summer weekend that captures everything we love about the indie festival experience. From its grassroots charm and random fun (you might go from headbanging to an orchestra to laughing along with stand-up comedy) to a lineup mixing established icons and breakout talent, Truck strikes a balance that few festivals achieve. Whether you’re there for the headliners or hunting for your new favourite band, you’re in for a treat at “your favourite artists’ favourite festival”. Grab a pint, soak up the good vibes, and enjoy the show – <strong>see you down on the farm!</strong></p></div><iframe style="border-radius:12px" src="https://open.spotify.com/embed/playlist/4zVMG9VmD2Zyi1lIZ7M25T?utm_source=generator" width="100%" height="352" frameBorder="0" allowfullscreen="" allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture" loading="lazy"></iframe>',
  'Truck Festival may be smaller than the likes of Glastonbury, but it packs in huge heart and character. This beloved Oxfordshire weekender has a grassroots, village fate vibe that’s truly one-of-a-kind. It’s big and varied enough to never get boring, yet intimate enough to feel friendly rather than o',
  'Feats.',
  '2025-04-04 10:00:00',
  '',
  '',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Turnstile announce UK dates for Autumn Tour',
  'turnstile-announce-uk-dates-for-autumn-tour',
  '<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/0cb14d7e-7ae8-4fdb-af08-c55ad51817b7/TURNSTILE-NEVER-ENOUGH-UK-European-tour-poster.jpg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Following a string of festival appearances and a pretty unforgettable Glasto set, Turnstile have confirmed they’ll be back in the UK this November for a headline run. It’s loud, it’s fast, and it’s going to be very sweaty.</p><p class="" style="white-space:pre-wrap;">They’ll be hitting three major UK cities with support from <a href="https://open.spotify.com/artist/4Gmrt82h2vjGjnp67SG5Nw?si=H8WLJYbCQ--JJssUwKj7qA"><span style="text-decoration:underline"><strong>High Vis</strong></span></a> and <a href="https://open.spotify.com/artist/4UVlSeEFDPmlkYKaRMRoOz?si=gqlNgs9LTDaI08uq8TkmSw"><span style="text-decoration:underline"><strong>The Garden</strong></span></a> on select dates. If you’ve been waiting to see the Baltimore band in a room full of people losing their minds, this is your shot.</p><p class="" style="white-space:pre-wrap;">Here’s where and when it’s going down:</p><ul data-rte-list="default"><li><p class="" style="white-space:pre-wrap;"><strong>2 Nov</strong> - Glasgow, O2 Academy</p></li><li><p class="" style="white-space:pre-wrap;"><strong>3 Nov</strong> - Manchester, Depot Mayfield</p></li><li><p class="" style="white-space:pre-wrap;"><strong>5 Nov</strong> - London, Alexandra Palace</p></li><li><p class="" style="white-space:pre-wrap;"><strong>31 Oct</strong> - Dublin, National Stadium</p></li></ul><p class="" style="white-space:pre-wrap;">No word yet on surprise guests, but with this line-up already locked, it’s looking like one of those tours people talk about for a while.</p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Turnstile came up through Baltimore’s hardcore scene and have since grown into one of the most exciting live bands around. Led by frontman Brendan Yates, with Franz Lyons, Daniel Fang, Pat McCrory, and new member Meg Mills, they’ve built a sound that pulls from punk, rock, and beyond—without ever feeling forced.</p><p class="" style="white-space:pre-wrap;">Their latest album <a href="https://open.spotify.com/album/52yD51X7yDinwlg6tbCtpP?si=2iCWzimgR9ytHrrUsMyd_Q"><span style="text-decoration:underline"><strong><em>Never Enough</em></strong></span></a> dropped in June and lands with a sense of focus and ease they’ve grown into over time. Tracks like “<a href="https://open.spotify.com/track/0k9JIBszlCqCa4SpXI353F?si=b474fe75af1e4421"><span style="text-decoration:underline"><strong>Birds</strong></span></a>” and “<a href="https://open.spotify.com/track/0vbdCsYHg1by09QKOGO4PR?si=1d36d2e8c1af40bf"><span style="text-decoration:underline"><strong>Seein’ Stars</strong></span></a>” are already slotting into their sets, adding new weight without losing the energy they’re known for. Whether it’s a packed theatre or a huge room like Ally Pally, Turnstile still manages to make the whole place move as one.</p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Pre-sale kicks off 10am on Tuesday 2 July, with general sale opening 10am Thursday 4 July. Set a reminder. Sell-outs feel likely.</p></div><script charset="utf-8" src="https://widget.bandsintown.com/main.min.js"></script><a class="bit-widget-initializer" data-artist-name="Turnstile" data-display-local-dates="true" data-display-past-dates="false" data-auto-style="false" data-text-color="#000000" data-link-color="#00b4b3" data-background-color="rgba(0,0,0,0)" data-display-limit="5" data-display-start-time="true" data-link-text-color="#FFFFFF" data-display-lineup="false" data-display-play-my-city="true" data-separator-color="rgba(255, 255, 255, 0.5)"></a><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><br><br><br></p></div>',
  'Following a string of festival appearances and a pretty unforgettable Glasto set, Turnstile have confirmed they’ll be back in the UK this November for a headline run. It’s loud, it’s fast, and it’s going to be very sweaty.',
  'Feats.',
  '2025-07-02 10:00:00',
  'Tour, Live Music, Artist Showcase',
  '/images/articles/TURNSTILE-NEVER-ENOUGH-UK-European-tour-poster.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Turnstile Live @ Depot Mayfield Manchester- 03.11.2025',
  'turnstile-live-depot-mayfield-mancehster-03-11-2025',
  '[caption id="" align="alignnone" width="1080"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/a45b4df4-3a6f-4bfc-adb2-68611dda1d05/TurnstileSoldout+tour+with+a+stacked+line-up+of+supports%2C+Grammy+nominations+across+three+differ.jpg?format=original" alt=" Image Credit: @markybymarc on instagram "/>  Image Credit: @markybymarc on instagram [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">The hardcore takeover of Depot Mayfield in Manchester was one of the most exciting things to happen this year. The venue opened their doors to 10,000 Turnstile fans on their Never Enough Tour. There was a huge buzz from the crowd before they had even made it into the venue, and you could really feel the excitement.</p><p class="" style="white-space:pre-wrap;">First up were High Vis, a rising band from London. One drum hit in, and the crowd were already pushing forward eager to watch their set. They had the crowd bobbing their heads and dancing, while playing favourites like ‘Walking Wires,’ ‘Trauma Bonds,’ ‘Drop Me Out,’ and ‘Minds Lie.’ The band had so much energy while on stage and reminded everyone why they are quickly becoming one of the UK’s most exciting punk bands — raw, tight, and bursting with confidence. They didn’t just warm up the room; they set the venue on fire, which continued through the whole night. </p></div>


  
       [caption id="" align="alignnone" width="1080"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1d961f81-e3f3-4fe1-b12e-e1303f3fe767/TurnstileSoldout+tour+with+a+stacked+line-up+of+supports%2C+Grammy+nominations+across+three+differ%282%29.jpg?format=original" alt=" Image Credit: @markybymarc on instagram "/>  Image Credit: @markybymarc on instagram [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Next up, California’s experimental punk-rock duo The Garden brought their signature unpredictability. The heavy thumping bass went right through you during their set,&nbsp; They delivered a chaotic, and super energetic set, that was thoroughly enjoyed by the audience. Their tracks landed with full force, songs such as ‘Filthy Rabbit Hole’ and ‘ The Nightmare’ had the crowd going wild at the front of the venue. They kept the crowd entertained and everyone seemed to really enjoy their set. </p><p class="" style="white-space:pre-wrap;">By the time Turnstile took the stage, Depot Mayfield felt electrified. The band launched into ‘NEVER ENOUGH’ instantly igniting the massive room. Despite performing to a packed 10,000-cap audience, Turnstile’s raw, intimate energy made the show feel like an intimate gig at a dive bar. </p><p class="" style="white-space:pre-wrap;">The setlist was a great blend of older hardcore songs and some newer ones. Bursts of energy came from ‘T.L.C,’ ‘BIRDS,’ ‘SEEIN’ STARS,’ ‘Real Thing,’ ‘Fazed Out,’ and ‘ALIEN LOVE CALL.’ The singer jumping around the stage, paired with the band’s explosive playing and heavy drum solos, kept the crowd locked in from start to finish.</p></div>


  
       [caption id="" align="alignnone" width="1080"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1e3eac5c-fd94-439a-a79a-3fa10aa73fdc/TurnstileSoldout+tour+with+a+stacked+line-up+of+supports%2C+Grammy+nominations+across+three+differ%283%29.jpg?format=original" alt=" Image Credit: @markybymarc on instagram "/>  Image Credit: @markybymarc on instagram [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">One of the night’s most memorable moments arrived during ‘SEEIN’ STARS’ when a disco ball was projecting all these flickering lights across the ceiling of the venue. The combination of the melody, and floaty guitar chords created a euphoric wave across the venue, chilling everyone out after the sweaty mosh of the rest of the gig —perfectly capturing Turnstile’s uncanny ability to make every person in the room feel connected to the music and to each other no matter what the song they are playing is. Turnstile proved exactly why they stand out in today’s melodic hardcore landscape. Every element—sound, light, energy—worked together to make this Monday night feel like one of the most unforgettable Hardcore shows Manchester has witnessed in years.</p><p class="" style="white-space:pre-wrap;">&nbsp;</p></div>',
  'The hardcore takeover of Depot Mayfield in Manchester was one of the most exciting things to happen this year. The venue opened their doors to 10,000 Turnstile fans on their Never Enough Tour. There was a huge buzz from the crowd before they had even made it into the venue, and you could really feel',
  'Feats.',
  '2025-11-24 15:00:00',
  'Live Music, Gig Review, editorial',
  '/images/articles/TurnstileSoldout+tour+with+a+stacked+line-up+of+supports%2C+Grammy+nominations+across+three+differ.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Twenty One Pilots Breach Tour: Will It Skip the UK/EU?',
  'twenty-one-pilots-breach-tour-will-it-skip-the-uk-eu',
  '[caption id="" align="alignnone" width="1618"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/c06ea5a2-93cc-404d-ae0d-0100fed0c1a9/Tyler+Statement.png?format=original" alt=" (Tyler Joseph Statement Via  Instagram ) "/>  (Tyler Joseph Statement Via  Instagram ) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">With ‘<a href="https://top.lnk.to/drumshow" target="_blank">Drum Show</a>’ due to release today, the second single from their up-coming album ‘<a href="https://open.spotify.com/prerelease/3EsYM7LoyJtJbdZYPx3N4U?si=a2dc96113fad4694" target="_blank">Breach</a>’, we thought we’d go through the recent statement from Tyler Joseph that has left fans divided after posting a candid message about the Breach tour. “<em>We aren’t giving Breach a proper world tour,</em>” he wrote, before adding, “<em>after North America, I have no idea when we’ll tour again, other than maybe some festivals next year.</em>” While the message wasn’t framed as a farewell, it did confirm what many feared: there are currently no plans for the duo to take their new album to Europe or the UK.</p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">The reaction from fans this side of the Atlantic has been one of frustration and disappointment. Breach is set to be the closing chapter of the Dema story, a narrative spanning more than a decade across multiple albums, and many feel it’s unfair to leave such a significant conclusion without a proper run of shows in Europe. The band’s Clancy Tour earlier this year included London, Manchester and Glasgow, but this time Joseph’s words suggest fans will have to pin their hopes on summer festival appearances at best.</p><p class="" style="white-space:pre-wrap;">There’s also wider speculation about what this means for the band’s future. Rumours have circulated for months about twenty one pilots’ relationship with their longtime label, Fueled By Ramen. With Breach arriving as the duo’s eighth record, some believe this could mark the end of their contract, potentially explaining why the campaign feels smaller in scale than past cycles. The idea of a hiatus, or at least a period of regrouping, also hangs over Joseph’s post-though he was careful to stress, “<em>I’m not saying this is our last tour ever.</em>”</p></div>


  
      <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/727fe83c-9cc8-4d6a-b25b-d94ca4d92969/27zqv02znc1f1.jpeg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Hints of a break aren’t new territory for the band. Long-time fans will remember the symbolic silence that followed Blurryface, when they disappeared for nearly a year before returning with Trench. More recently, the duo themselves leaned into that memory when teasing the Clancy anniversary, posting the same cryptic “eyes” imagery that originally marked their 2017-2018 hiatus. For many, Joseph’s new comments feel like a continuation of that cycle: step away, regroup, then re-emerge with a new era.</p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">But for fans who’ve followed the Dema saga since its earliest clues, the idea that its ending may never be performed live in the UK or Europe stings. This uncertainty mirrors moves from other major acts. Bring Me the Horizon, for instance, have spoken openly about taking time away after POST HUMAN: NeX GEn, balancing selective festival slots with a break from touring. The difference here is that twenty one pilots are tying off a story arc fans have invested in for over ten years, making the absence of EU dates feel even more pronounced.</p><p class="" style="white-space:pre-wrap;">As it stands, Breach will arrive on 12 September, closing a narrative chapter unlike any other in modern alternative music. Whether UK and EU fans will get the chance to experience it live remains unknown - but Joseph’s carefully chosen words suggest the story of twenty one pilots is far from over.</p></div>',
  'With ‘Drum Show’ due to release today, the second single from their upcoming album ‘Breach’, we thought we’d go through the recent statement from Tyler Joseph that has left fans divided.',
  'Feats.',
  '2025-08-18 16:00:00',
  'News, Tour, Album Release',
  '/images/articles/Tyler+Statement.png',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Twenty One Pilots Clancy Tour Review &amp; Recap',
  'twenty-one-pilots-clancy-tour-review-recap',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><strong>Editorial Note:</strong></p><p class="" style="white-space:pre-wrap;">Since the writing of this article Twenty One Pilots have Announced their up-coming album “Breach” coming out in September, with the first song “Contract” releasing June 12th 2025.</p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Twenty One Pilots’ Clancy World Tour has proven to be a triumph, spanning 22 Countries, across 4 continents, the tour was the band''s biggest tour to-date. From August 2024, to May 2025 Tyler Joseph &amp; Josh Dun played a total of 73 shows in more than 60 cities - every show bridging a high energy, immersive concert to their fans!&nbsp; The tour kicked off in Denver, Colorado and would come to an end more than nine months later with a two-night epic finale at the renowned O2 Arena in London.&nbsp;</p></div>


  
       [caption id="" align="alignnone" width="1080"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/5d2cc801-5699-44ef-8e08-16e3310fac73/491440710_18045906593579740_3488338911094287523_n.jpg?format=original" alt=" Image Credit: Gracie Hall - @gracroc "/>  Image Credit: Gracie Hall - @gracroc [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Billed as a “<em>Massive Global Headliner tour”</em> - the band''s Biggest tour ever - the Clancy Tour Lived up to its name. In Fall 2024 the duo started their run across North America, supported by Balu Brigada, packing arenas across the US &amp; Canada. Due to record high demand second nights were added in cities like; Denver, Dallas, Boston &amp; the bands hometown Columbus, Ohio, which saw an impressive three-night stand!<br><br>After a brief break they touched down in New Zealand and Australia in late 2024. Early 2025 Marked a milestone as the band launched its first-ever run through South America and Mexico, playing unbelievable sets night after night in Bogotá, Santiago, São Paulo, Buenos Aires, just to name a few.<br><br>The Final Leg of the tour was the Europe, which rolled around in Spring 2025, with sold out arenas spanning Germany, Poland, Czechia, Austria, Switzerland, Italy, Spain, France, Netherlands, Ireland, Scotland &amp; England - </p></div><hr /><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><strong>Highlights</strong></p></div>


  
       [caption id="" align="alignnone" width="1080"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/0eefa98c-7735-403a-bb0f-82ff2d008399/497771614_18046622417579740_7251753305439959741_n.jpg?format=original" alt=" Image Credit: Gracie Hall - @gracroc "/>  Image Credit: Gracie Hall - @gracroc [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Beyond the record setting stats, the Clancy tour delivered plenty of unforgettable moments. Twenty One Pilots’ kicked off the very first show in Denver with an extensive 28-song setlist that Thrilled the Die-hard fans &amp; newcomers alike! Fans were treated to the live debut of four new songs (following the “An Evening with Twenty One Pilots” Mini Release tour just after the release of Clancy in May 2024), including “Vignette” and “Paladin Strait”. Through the tour the band struck a balance between their new releases and the existing fan favorites- ensuring the keep the punters on their toes with frequent changes to the setlists from gig to gig!</p><p class="" style="white-space:pre-wrap;">Throughout each show the duo made sure that no single person felt like they weren''t included in the performance, this time they broke out two smaller “b-stages” platforms on either side of the arenas, here is where they would interact with fans, bring back old (or even some unreleased!) songs, and perform remixed versions of some classics!&nbsp; Early on in the tour they played “Old song Medley”, which was a remix of very early fan favorite songs such as “Addicted with a Pen“, “Forest” and “Slowtown”, which was a real nostalgic treat for the long-term listeners in the crowd!</p></div>


  
       [caption id="" align="alignnone" width="1080"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/b66e54dd-778f-47ca-a516-1afe6754fd26/497387396_18046622507579740_3139456768425903272_n.jpg?format=original" alt=" Image Credit: Gracie Hall - @gracroc "/>  Image Credit: Gracie Hall - @gracroc [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">One standout favourite across the shows was when the duo performed “Ride”, inviting a young person onto the platform to sing with Tyler. Without fail, this melted the hearts of every single person in the arena &amp; will definitely be a core memory for the kids that got to choose!</p><p class="" style="white-space:pre-wrap;">The Twenty One Pilots fanbase is a defining element of the band! With thousands of fans donning the signature red/yellow stripes, with hundreds of custom bandito outfits, there really is no fan base that has the same kind of passion for a band! During the Sets despite the new songs being relatively new, the entire arena knew <em>all</em> the words! Even filling in fan-made gaps like quietly singing the lyrics to Trenches “Leave the City”, in the gap within “Paladin Straight”, and of course the fan favourite “<em>Here we Fucking Go”</em><strong><em> </em></strong>chant just before the epic finale of the Iconic “Trees”.</p><p class="" style="white-space:pre-wrap;"><br>In the final three gigs of the tour there was an extraordinary event in which one overly devoted attendee stole one of the bands drums at the end of the show! Fans quickly mobilised to help track it down &amp; within less than 24 hours the drum was recovered without issue! The band the next day made light of the situation with quick jokes &amp; a comically large chain attached to the drums! Incidents like this, along with the deafening sing-alongs at every stop, underscored the passionate bond between Twenty One Pilots and their audience.</p></div><hr /><blockquote class="twitter-tweet" data-dnt="true" align="center"><p lang="en" dir="ltr">it’s not.<br>the show is a flashback.<br>like an entire life passing by.<br>reminding us why we fight right before we do. <a href="https://t.co/8Wa2L8klMZ">https://t.co/8Wa2L8klMZ</a></p>&mdash; tyler jøseph (@tylerrjoseph) <a href="https://twitter.com/tylerrjoseph/status/1804571290793034150?ref_src=twsrc%5Etfw">June 22, 2024</a></blockquote>
<script async src="https://platform.twitter.com/widgets.js" charset="utf-8"></script><div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;"><strong>A Theatrical Cinematic Experience</strong><br>Critics and Fans alike have always praised the Pilots for their ambitious productions and showmanship, in that vein the Clancy tour was no different! Each concert was far more than a typical run-through of songs, as Tyler described in a reply to a <a href="https://x.com/tylerrjoseph/status/1804571290793034150"><span style="text-decoration:underline">tweet “The Show is a flashback. Like an Entire Life passing by. Reminding us why we fight right before we do.”</span></a> </p><p class="" style="white-space:pre-wrap;">The stage itself became a dystopian playground, with a mixture of nostalgic visuals &amp; conceptual lore telling- Tyler &amp; Josh built a story through the shows, each show dropping hits &amp; secrets, further building into the lore of Dema.</p></div>


  
       [caption id="" align="alignnone" width="1080"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/4ef3d464-5795-4d79-a17e-ee909fabf6e8/497720585_18046540334579740_4416335569285117865_n.jpg?format=original" alt=" Image Credit: Gracie Hall - @gracroc "/>  Image Credit: Gracie Hall - @gracroc [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">In the third quarter of the set, the duo took a moment to feed into the on-going storyline, with Torch-bearer (Josh), wearing the classic Bandito yellow stripes, walking through the crowd over to Clancy (Tyler), at which point he is handed the Clancy Era Red-striped jacket. Each night the duo changed the performance slightly, eventually ending with Clancy ignoring Torch-bearer, massively fueling speculation &amp; rumours from the band''s fan-base!<br><br>Whilst that was the most “Lore Heavy” element of the show, it wasn''t the only theatrical element - during Car-Radio Tyler would vanish from the main stage only to as if by magic appear high in the rafters of the arena.</p><p class="" style="white-space:pre-wrap;">Each show closed with the band’s iconic stunt: both members pounding away on portable drums held by the crowd during the exhilarating finale “Trees,” amid confetti cannons and roaring cheers. It was a tear-inducing climax that highlighted the joyful communion between the band and their fans.</p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><p class="" style="white-space:pre-wrap;"><strong>A Triumphant Recap of the Era</strong></p><p class="" style="white-space:pre-wrap;">All in all, the Clancy World Tour has been an engaging, high-octane journey that solidified Twenty One Pilots’ reputation as one of music''s most electrifying live acts. Endless reviews hailed the tour as a “<em>masterclass in immersive storytelling, electrifying visuals, and heartfelt connection”, </em>emphasizing that the band’s live show operates <em>“in a league entirely its own”.</em></p><p class="" style="white-space:pre-wrap;"><br>Night after night, Tyler &amp; Josh gave everything, live vocals, incredible musical talent, all delivered with energy didnt leave a single dry eye in the house. With the explosive first notes in Denver to the final confetti fall in London, the Clancy Tour was both a celebration of the new album and a (deserved) victory lap of the band at the peak of its powers. Leaving the clique exhilarated, emotional, and excited to see what the band does next!</p></div>',
  'Twenty One Pilots’ Clancy World Tour has proven to be a triumph, spanning 22 Countries, across 4 continents, the tour was the band''s biggest tour to-date. From August 2024, to May 2025 Tyler Joseph &amp; Josh Dun played a total of 73 shows in more than 60 cities - every show bridging a high energy, ',
  'Feats.',
  '2025-05-23 10:00:00',
  'Gig Review, Album Review, Tour, Tour Review, Artist Showcase',
  '/images/articles/491440710_18045906593579740_3488338911094287523_n.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'VLURE set us free as we follow them through the release of their new single CUT IT.&nbsp;',
  'vlure-set-us-free-as-we-follow-them-through-the-release-of-their-new-single-cut-itnbsp',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">The five piece Glaswegian post punk band release a new single <strong><em>Cut It</em></strong><em> </em>which releases Friday the 20th.</p><p class="" style="white-space:pre-wrap;">In a true Vlure fashion the new single mixes their post punk sound with an electronic beat creating a sound that is unique to them.&nbsp;</p><p class="" style="white-space:pre-wrap;">Starting with a bang (literally), <strong><em>Cut it</em></strong><em> </em>takes you on a ride between the startling guitars and catchy chorus, not forgetting Hamish’s hard cutting vocals that will never fail to grab the listener’s attention.&nbsp;</p></div>


  
       [caption id="" align="alignnone" width="3513"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/dc9cbd85-b7ab-4f56-a9bd-90a46e718dbc/Vlure+10.01.2022+%2830+of+34%29.jpg?format=original" alt="   Louis Hitchcock (LouisHitchPhotos, Feats.)   "/>    Louis Hitchcock (LouisHitchPhotos, Feats.)   [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">My personal favourite part of the song is the first verse where Vlure tells the audience to take their hand to the promised land, that the listener will be set free if they follow them. When hearing this for the first time it made me want to surrender to the song, it made me put my trust in the creation they have worked on and I was not disappointed.</p><p class="" style="white-space:pre-wrap;">After seeing <strong><em>Cut It</em></strong><em> </em>performed live for the first time at Vlure’s gig, at the Lexington on November the 3rd I instantly knew it was the start of something big and I still believe that.&nbsp;</p><p class="" style="white-space:pre-wrap;">Vlure are one of the most, if not THE most exciting new band on the scene and you should all be paying close attention to them!<br></p><p class="" style="white-space:pre-wrap;">Grab some tickets to see them live supporting LYNKX on their upcoming tour.</p><p class="" style="white-space:pre-wrap;">https://myticket.co.uk/artists/diy-now-and-next-tour-2023</p></div>


  
       [caption id="" align="alignnone" width="3482"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/805e1abd-a366-4fe4-afad-d8a5f9054a77/Vlure+10.01.2022+%2832+of+34%29.jpg?format=original" alt="   Louis Hitchcock (LouisHitchPhotos, Feats.)   "/>    Louis Hitchcock (LouisHitchPhotos, Feats.)   [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Stream <strong>Cut it</strong> here: https://open.spotify.com/artist/0Ev1tqYsfzq2eF5qqXhkYm?si=8hvO0ZugSjSst-mfc3Bv5w&nbsp;</p></div>',
  'After first performing it live eight months ago, VLURE released their new single Cut it. The self produced banger is “all about false idolisation in the current world”.',
  'Feats.',
  '2023-01-20 00:00:00',
  'concert, Live Music, up and coming',
  '/images/articles/Vlure+10.01.2022+%2830+of+34%29.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'W.A.S.P Live @ The LCR Norwich 20.07.2025',
  'wasp-live-the-lcr-norwich-20-07-2025',
  '<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/760d6fca-6c2d-4743-8383-8126b26c08a5/_MG_0042+copy.jpg?format=original" alt=""/>
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">W.A.S.P came and the put on one strong show and brought the fans with them to prove it. You already know you’re going to be in for a treat when most of the fans have been seeing the band for 30+ years. A long standing career and dedicated fan base say a lot about a performer, and it definitely proved right for W.A.S.P.&nbsp;</p><p class="" style="white-space:pre-wrap;">The crowd was eager and ready to go from the minute doors opened, with the crowd getting involved and enjoying the support band Tailgunner and their electrifying set, with every member running around the stage during the performance; a real band to catch, with their songs matching their energy, it was hard to not feel like you wanted to join in. With a pre-warning for no crowd surfing before W.A.S.P arrived on stage, you really felt the energy from the audience and the need for commotion and perhaps a mosh pit or two.&nbsp;</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252218326-2TJGGC3L6PF4YN6RHWTH/%40shardsoflight_+-+Tailgunner+-+The+LCR+-+20-07-2025+-+002.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252218389-4QMKB7KCMAH5ABO5WDCR/%40shardsoflight_+-+Tailgunner+-+The+LCR+-+20-07-2025+-+003.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252219343-G29V9KE0XZ8AYNSIAF5G/%40shardsoflight_+-+Tailgunner+-+The+LCR+-+20-07-2025+-+004.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252219422-TPAUPVV6DTUBPPH5WB8K/%40shardsoflight_+-+Tailgunner+-+The+LCR+-+20-07-2025+-+005.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252220568-VC0C0ECM3WK8993KO2LD/%40shardsoflight_+-+Tailgunner+-+The+LCR+-+20-07-2025+-+006.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252220727-GI4GNYK7VLJI6Q0BS0EM/%40shardsoflight_+-+Tailgunner+-+The+LCR+-+20-07-2025+-+007.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252221568-L11YN3CHB7VXH7GPP8FZ/%40shardsoflight_+-+Tailgunner+-+The+LCR+-+20-07-2025+-+001.jpg?format=original" />
  

</div>
<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">W.A.S.P’s stage set up certainly caught your eye, with various cloth posters adorning the back of the stage with slogans and images, as well as a mic stand in the shape of a curved spine, adorned with a skull and crossbones in front of the mic itself.&nbsp;</p><p class="" style="white-space:pre-wrap;">Once they started playing you felt the energy in the room shift, with everyone feeling the music pulse through you, as the stage was seemingly taken over with such a presence you almost couldn’t do anything but marvel at them.&nbsp;</p><p class="" style="white-space:pre-wrap;">Although thankfully not witnessing any of their antics with raw meat being thrown around like they used to, it’s safe to say W.A.S.P have still got it.</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252192950-CK51H8A6W5ZNC18Y5Q4N/%40shardsoflight_+-+W.A.S.P+-+The+LCR+-+20-07-2025+-+001.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252193039-CV6UHG8TW19KNQ6LVT1U/%40shardsoflight_+-+W.A.S.P+-+The+LCR+-+20-07-2025+-+002.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252193966-1ZEYMBECEUXPM5BIOG0Y/%40shardsoflight_+-+W.A.S.P+-+The+LCR+-+20-07-2025+-+003.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252194160-PO4DXASJQ7WNS64QD4S0/%40shardsoflight_+-+W.A.S.P+-+The+LCR+-+20-07-2025+-+004.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252195197-QYVF1MXW3I0BXZUQDHUW/%40shardsoflight_+-+W.A.S.P+-+The+LCR+-+20-07-2025+-+005.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252195249-U0P1HSDLYGT6FL64INTJ/%40shardsoflight_+-+W.A.S.P+-+The+LCR+-+20-07-2025+-+006.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252196225-MQKJSR6Y2BCK0790GFNJ/%40shardsoflight_+-+W.A.S.P+-+The+LCR+-+20-07-2025+-+007.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252196308-T24VA1JCBDQRXYZ7I976/%40shardsoflight_+-+W.A.S.P+-+The+LCR+-+20-07-2025+-+008.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252197284-RSY1G5EY6HES9DXORKNU/%40shardsoflight_+-+W.A.S.P+-+The+LCR+-+20-07-2025+-+009.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1754252197704-G80HV3F6KM2NCIIKWCSF/%40shardsoflight_+-+W.A.S.P+-+The+LCR+-+20-07-2025+-+010.jpg?format=original" />
  

</div>',
  'W.A.S.P came and the put on one strong show and brought the fans with them to prove it. You already know you’re going to be in for a treat when most of the fans have been seeing the band for 30+ years. A long standing career and dedicated fan base say a lot about a performer, and it definitely prove',
  'Feats.',
  '2025-08-04 12:00:00',
  'Live Music, Gig Review',
  '/images/articles/_MG_0042+copy.jpg',
  'publish'
);
