INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'When Rivers Meet Live @ Adrian Flux Waterfront 29.05.2025',
  'when-rivers-meet-live-adrian-flux-waterfront-29-05-2025',
  '<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748775491232-IBFUY2312SHYUWTY60L6/%40shardsoflight_+-+Pistol+Daisys+-+Adrian+Flux+Waterfront+-+29-05-2025+-+002.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748775491284-W3RG255WIN1K95KVTUK4/%40shardsoflight_+-+Pistol+Daisys+-+Adrian+Flux+Waterfront+-+29-05-2025+-+003.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748775492527-PYYUQPN1OBIPPDODXU04/%40shardsoflight_+-+Pistol+Daisys+-+Adrian+Flux+Waterfront+-+29-05-2025+-+004.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748775492655-7YFXL82TCFP4N4F03G4R/%40shardsoflight_+-+Pistol+Daisys+-+Adrian+Flux+Waterfront+-+29-05-2025+-+005.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748775493956-RPMNK3S6AI134GG24F04/%40shardsoflight_+-+Pistol+Daisys+-+Adrian+Flux+Waterfront+-+29-05-2025+-+006.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748775494139-BQFM1DZKRGMTERVJJ63F/%40shardsoflight_+-+Pistol+Daisys+-+Adrian+Flux+Waterfront+-+29-05-2025+-+007.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748775495261-W2MO2RXE09NGTD3141GJ/%40shardsoflight_+-+Pistol+Daisys+-+Adrian+Flux+Waterfront+-+29-05-2025+-+001.jpg?format=original" />
  

</div>
<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">When Rivers Meet on their ‘Addicted To You’ release week tour was always promised to be great, with their album reaching number 4 on the top charts whilst being a fully independent band - their fans were sure to turn out. </p><p class="" style="white-space:pre-wrap;">And turn out they did, with the room already packed and ready to go for the support act, Pistol Daisys; an electrifying Scottish band from Glasgow who captivated the room with their witty charm and incredible performance, creating the perfect atmosphere for When Rivers Meet to enter into. </p><p class="" style="white-space:pre-wrap;">Once When Rivers Meet arrived you could feel the energy emanating from the audience, everyone so excited to be a part of this moment. The band emerged in a haze of mist and green lighting, casting strong shadows and creating the perfect entrance. The show ploughed on with hit after hit, with some songs including pieces on the violin - casting the perfect atmosphere and tying together nicely with the ever changing variety of&nbsp;lighting&nbsp;used.</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748775547206-KWITH0TXNV7PPLMPZ0ED/%40shardsoflight_+-+When+Rivers+Meet+-+Adrian+Flux+Waterfront+-+29-05-2025+-+001.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748775547275-HB7LTXZALSCKRDV5UDY0/%40shardsoflight_+-+When+Rivers+Meet+-+Adrian+Flux+Waterfront+-+29-05-2025+-+002.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748775548860-L068NDT6T9ALFWYWYSVX/%40shardsoflight_+-+When+Rivers+Meet+-+Adrian+Flux+Waterfront+-+29-05-2025+-+003.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748775548783-VKAH1QKJYVKO97ZU1Q5F/%40shardsoflight_+-+When+Rivers+Meet+-+Adrian+Flux+Waterfront+-+29-05-2025+-+004.jpg?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748775550203-IHTBNZ0S0IBCEOMYWPFX/%40shardsoflight_+-+When+Rivers+Meet+-+Adrian+Flux+Waterfront+-+29-05-2025+-+005.jpg?format=original" />
  

  
