INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Welcome to THEIR House: Yonaka at The Great Escape',
  'yonakatge',
  '[caption id="" align="alignnone" width="4240"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/b5aa5680-8790-4ec4-9c44-a4acf3f53f32/DSC03299.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Brighton''s own, 3-piece alternative rock trio return to The Great Escape for the first time in five years. This is also their first time back in Brighton since 2021. They return to Chalk to fill out the iconic venue again this year. We caught up with Yonaka to discuss everything “Welcome To My House”, upcoming music, Brighton nights out, Tonight Matthew, and everything in between.</p><p class="" style="white-space:pre-wrap;">&nbsp;</p><p class="" style="white-space:pre-wrap;">Three singles, ‘Welcome to my house’, ‘Panic’ and ‘Give Me My Halo’ have been released from their upcoming 7-song EP. During our chat with Yonaka they teased that one more single will be dropped before the EP comes out. Although originally teasing ‘By The Time You’re Reading This’ being the next single to come off of The EP, ‘Give Me My Halo’  was instead released last week, a beautiful anthem that allows Teresa’s Vocals to be showcased throughout the track. A slow mellow entry that builds into an ethereal atmosphere.</p></div>


  
       [caption id="" align="alignnone" width="3467"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/733df11c-d716-4186-924f-f1040137d51e/IMG_0430.JPG?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Welcome to my house is the title track of the unreleased EP, a song that Teresa says ‘it’s me, I’m the house and all these experiences are guests - it''s nice to remember that these (negative) feelings won’t last forever. It’s like a therapy session.’&nbsp;</p><p class="" style="white-space:pre-wrap;">The track sees Teresa go on a journey from self-loathe, working through that and finally seeing herself in this new positive light.&nbsp;</p><p class="" style="white-space:pre-wrap;">‘When I first made the loop, I didn’t know if it was a Yonaka song’, Alex says But it’s so clear how well ‘Welcome To My House’ fits Yonaka - A song with power embedded within the lyrics, and one that I think a lot of people can relate to.&nbsp;</p></div>


  
       [caption id="" align="alignnone" width="3805"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/7cb8c3e6-6d3e-477c-934a-1a13e81958cd/IMG_0417.JPG?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Their set opened up with ‘Ordinary’. Instant energy buzzed throughout the crowd. The barrier rammed - strobe lights flying over the crowd and screams blast through the ceiling as Yonaka walks out on stage.&nbsp;</p><p class="" style="white-space:pre-wrap;">As the set continued on, The band Debuted ‘By The Time You’re Reading This’, off the upcoming EP. The Track is yet to be released but everyone in the crowd treated it as if it were a Yonaka classic, hanging onto every lyric sang.</p><p class="" style="white-space:pre-wrap;">“Seize The Power” broke through during the set with a powerhouse song, sassy &amp; assertive with a catchy chorus - a great way to finish off their headline set at The Great Escape.</p></div>


  
       [caption id="" align="alignnone" width="6000"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/92ac90da-d0c0-4b86-b4fe-5885ab3b5517/yonaka29.JPG?format=original" alt=" Sophie Bingham (displacedimages/FEATS) "/>  Sophie Bingham (displacedimages/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">“Seize The Power” has recently hit 30 million after appearing in marvels recent ‘SHE-HULK’. The track went viral on TikTok and is now listened to by thousands every day. ‘It''s just stats but it’s nice to see’ George says while explaining how nice it is to see that people enjoy their music.</p><p class="" style="white-space:pre-wrap;">Returning home is always nice’ all three members are excited to play their own slot after an insane run with Palaye Royale took them to 26 different countries, returning home after a run like that anyone would be nervous but no, Yonaka are buzzing and it translates perfectly across the Stage. Confidence oozes out of them during their set, moving perfectly in sync. Yonaka is a band that never disappoints.&nbsp;<strong><em> </em></strong></p><p class="" data-rte-preserve-empty="true" style="white-space:pre-wrap;"></p><p class="" style="white-space:pre-wrap;">Check out the full Interview and Yonakas Latest single Below:&nbsp;</p></div><iframe class="embedly-embed" src="//cdn.embedly.com/widgets/media.html?src=https%3A%2F%2Fwww.youtube.com%2Fembed%2FNC0OwHh17co%3Ffeature%3Doembed&display_name=YouTube&url=https%3A%2F%2Fwww.youtube.com%2Fwatch%3Fv%3DNC0OwHh17co&image=https%3A%2F%2Fi.ytimg.com%2Fvi%2FNC0OwHh17co%2Fhqdefault.jpg&key=61d05c9d54e8455ea7a9677c366be814&type=text%2Fhtml&schema=youtube" width="854" height="480" scrolling="no" title="YouTube embed" frameborder="0" allow="autoplay; fullscreen" allowfullscreen="true"></iframe><iframe style="border-radius:12px" src="https://open.spotify.com/embed/album/5aQsFdfnxekkMoyXnLyXeS?utm_source=generator&theme=0" width="100%" height="352" frameBorder="0" allowfullscreen="" allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture" loading="lazy"></iframe>',
  'Brighton''s own, 3-piece alternative rock trio return to The Great Escape for the first time in five years. This is also their first time back in Brighton since 2021. They return to Chalk to fill out the iconic venue again this year. We caught up with Yonaka to discuss everything “Welcome To My House',
  'Feats.',
  '2023-07-06 11:39:14',
  'Live Music, Gig Review, Interview',
  '/images/articles/DSC03299.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'You Me At Six: Debut their 7th Studio Album Truth Decay, fill Iconic Alexandra Palace with mosh pits and bring everyone to tears all during one set.',
  'youmeatsixtruthdecayatalexandrapalace',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">You Me at Six have proved time and time again that they can do it all and with a 7th studio album in their pocket and 19 years in the game, there''s no surprise that they put on an absolute show.</p></div>


  
       [caption id="" align="alignnone" width="2768"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/e6d21e89-ef7c-4b74-b38a-d2ab1c0128e7/DSC01303_2.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">The Bill was filled with London''s favourite upcoming band Bears in Trees, followed by American Rock Band The Maine who lit up the stage and brought on Charlotte Sands for a special appearance of ‘Loved You A Little’. Followed by the band that''s similar to marmite, you either love or loathe them, Waterparks. The set bought all fan favourites to the UK playing ‘i miss having sex but at least i don’t want to die” a song that ensures everyone to be singing it’s catchy chorus (even if you’re not a fan) and Blackbear collab ‘FUCK ABOUT IT’. It almost felt like a mini warped tour topped off by YMAS at the end of the evening.</p></div>


  
       [caption id="" align="alignnone" width="2442"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/098a22de-9a6a-483f-a516-88159150b7d2/DSC01117_1.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">You Me at Six then graced the stage with their single ‘Deep Cuts’ from their latest album ‘Truth Decay’. With this being the second headline appearance at Ally Pally, this time YMAS have come back much harder. With an insane production and multiple stage levels, they were there to show exactly why they have been doing this for almost two decades. Followed up by fan favourite ‘Fresh Start Fever’ coming off of their 5th studio album, Cavalier - the crowd were in awe and went crazy as pits opened up all over the iconic venue. Classics were played all night, ‘Liquid Confidence’ off of their 2010 album “Hold Me Down” had everyone screaming back at frontman Josh Franceschi. Highlighting their newest songs like ‘HeartLESS’, ‘Mixed Emotions’ and the less popular ‘God Bless the 90’s Kids’ lyrically different from their usual sound, and generally not my thing however the crowd still shouted right back at the band.</p></div>


  
       [caption id="" align="alignnone" width="2768"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/8b409b56-fbf1-414a-bebf-be1e98a32f40/DSC01240_1.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Mid-set Josh Franchesci announced that the set was headed into its ‘heavier part’ with the crowd riled up, circle pits everywhere ‘BITE MY TONGUE’ blares over, a personal favourite of mine, this studio track features bring me the horizon’s, Oli Sykes while we were not graced with his presence Rou Reynolds from Enter Shikari surprised the crowd during ‘No Future, Yeah Right’ and it was what everybody needed, a skyrocket in energy surged throughout Alexandra Palace as both Francheschi and Reynolds went mental on stage.</p><p class="" style="white-space:pre-wrap;">The set then took an emotional turn, slowed down with legendary single ‘Take On the World’ which hot number 1 on the Uk rock charts, the 5th for You Me at Six, iphone flashlights lit the venue up while everyone sang word for word, followed by heart-string tug rendition of ‘No One Does It Better’ from Francheschi and Guitarist Chris Miller.</p></div>


  
       [caption id="" align="alignnone" width="2768"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/29cfc30f-e5eb-46ec-beab-af2b1cdf93cb/DSC01394_1.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">The night ended on four last tracks, ‘SUCKAPUNCH’ and iconic ‘Underdog’ was the highlight at the end of the night, one last push of energy as everyone bounced back and forth before stooping off at the bars for water at the end of the show. Although their was moments during the set where the energy dropped overall You Me At Six never fail to disappoint, their set had something for everyone, and Alexandra Palace was filled to the brim. You Me At Six are a band that have you to see at least once in your lifetime, if they''re coming to a city near you then you should definitely pay them a visit.</p></div>


  
       [caption id="" align="alignnone" width="2768"]<img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/62cebd28-219c-44ac-8dfe-03f289d4591e/DSC01473.jpg?format=original" alt=" Tom Ellis (TJEphotos/FEATS) "/>  Tom Ellis (TJEphotos/FEATS) [/caption] 
  

<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Check out Truth Decay below.</p></div><iframe style="border-radius:12px" src="https://open.spotify.com/embed/album/1InYWNQZhu7U98emMWUdgW?utm_source=generator&theme=0" width="100%" height="352" frameBorder="0" allowfullscreen="" allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture" loading="lazy"></iframe>',
  'You Me at Six have proved time and time again that they can do it all and with a 7th studio album in their pocket and 19 years in the game, there''s no surprise that they put on an absolute show.',
  'Feats.',
  '2023-04-01 12:39:59',
  'Album Release, Review, Live Music',
  '/images/articles/DSC01303_2.jpg',
  'publish'
);
INSERT INTO articles (title, url_id, body, excerpt, author, publish_date, categories, cover_url, status) VALUES (
  'Zimmer90 Live @ Gorilla Manchester 09.05.2025',
  'zimmer90-live-gorilla-manchester-09-05-2025',
  '<div class="sqs-html-content" data-sqsp-text-block-content><p class="" style="white-space:pre-wrap;">Zimmer90''s performance at Manchester''s Gorilla on May 9, 2025, was a captivating blend of electronic and acoustic sounds that transformed the venue into an immersive acoustic journey. The duo''s dynamic stage presence and seamless transitions from melodic melodies to energetic dance beats kept the audience engaged throughout the evening. Fans praised the show as "very upbeat and loud," highlighting the vibrant atmosphere and the crowd''s enthusiastic response.</p></div>

<div class="image-gallery-wrapper">

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748433423977-KVPS2BE5C4GTXPRTBWZT/%40annarfilms+-+Gorilla+-+Zimmer90+-+09-05-2025+%289%29.JPG?format=original" />
  

  
   <img src="https://images.squarespace-cdn.com/content/v1/627907a6b74722549de2ec0c/1748433423930-0GMLWS3XNJE3PJC1HPLL/%40annarfilms+-+Gorilla+-+Zimmer90+-+09-05-2025+%2810%29.JPG?format=original" />
  

  
